#include "biblia.h"

void Biblia::Carregar2Samuel(Biblia* b) {
    b->dados[SAMUEL2].nome = _("2 Samuel");

    b->dados[SAMUEL2].capitulos[1].versos[1] = _("Depois da morte de Saul, tendo Davi voltado da derrota dos amalequitas e estando há dois dias em Ziclague,");
    b->dados[SAMUEL2].capitulos[1].versos[2] = _("ao terceiro dia veio um homem do arraial de Saul, com as vestes rasgadas e a cabeça coberta de terra; e, chegando ele a Davi, prostrou-se em terra e lhe fez reverência.");
    b->dados[SAMUEL2].capitulos[1].versos[3] = _("Perguntou-lhe Davi: Donde vens? Ele lhe respondeu: Escapei do arraial de Israel.");
    b->dados[SAMUEL2].capitulos[1].versos[4] = _("Davi ainda lhe indagou: Como foi lá isso? Dize-mo. Ao que ele lhe respondeu: O povo fugiu da batalha, e muitos do povo caíram, e morreram; também Saul e Jônatas, seu filho, foram mortos.");
    b->dados[SAMUEL2].capitulos[1].versos[5] = _("Perguntou Davi ao mancebo que lhe trazia as novas: Como sabes que Saul e Jônatas, seu filho, são mortos?");
    b->dados[SAMUEL2].capitulos[1].versos[6] = _("Então disse o mancebo que lhe dava a notícia: Achava-me por acaso no monte Gilboa, e eis que Saul se encostava sobre a sua lança; os carros e os cavaleiros apertavam com ele.");
    b->dados[SAMUEL2].capitulos[1].versos[7] = _("Nisso, olhando ele para trás, viu-me e me chamou; e eu disse: Eis-me aqui.");
    b->dados[SAMUEL2].capitulos[1].versos[8] = _("Ao que ele me perguntou: Quem és tu? E eu lhe respondi: Sou amalequita.");
    b->dados[SAMUEL2].capitulos[1].versos[9] = _("Então ele me disse: Chega-te a mim, e mata-me, porque uma vertigem se apoderou de mim, e toda a minha vida está ainda em mim.");
    b->dados[SAMUEL2].capitulos[1].versos[10] = _("Cheguei-me, pois, a ele, e o matei, porque bem sabia eu que ele não viveria depois de ter caído; e tomei a coroa que ele tinha na cabeça, e o bracelete que trazia no braço, e os trouxe aqui a meu senhor.");
    b->dados[SAMUEL2].capitulos[1].versos[11] = _("Então pegou Davi nas suas vestes e as rasgou; e assim fizeram também todos os homens que estavam com ele;");
    b->dados[SAMUEL2].capitulos[1].versos[12] = _("e prantearam, e choraram, e jejuaram até a tarde por Saul, e por Jônatas, seu filho, e pelo povo do Senhor, e pela casa de Israel, porque tinham caída à espada.");
    b->dados[SAMUEL2].capitulos[1].versos[13] = _("Perguntou então Davi ao mancebo que lhe trouxera a nova: Donde és tu? Respondeu ele: Sou filho de um peregrino amalequita.");
    b->dados[SAMUEL2].capitulos[1].versos[14] = _("Davi ainda lhe perguntou: Como não temeste estender a mão para matares o ungido do Senhor?");
    b->dados[SAMUEL2].capitulos[1].versos[15] = _("Então Davi, chamando um dos mancebos, disse-lhe: chega-te, e lança-te sobre ele. E o mancebo o feriu, de sorte que morreu.");
    b->dados[SAMUEL2].capitulos[1].versos[16] = _("Pois Davi lhe dissera: O teu sangue seja sobre a tua cabeça, porque a tua própria boca testificou contra ti, dizendo: Eu matei o ungido do Senhor.");
    b->dados[SAMUEL2].capitulos[1].versos[17] = _("Lamentou Davi a Saul e a Jônatas, seu filho, com esta lamentação,");
    b->dados[SAMUEL2].capitulos[1].versos[18] = _("mandando que fosse ensinada aos filhos de Judá; eis que está escrita no livro de Jasar:");
    b->dados[SAMUEL2].capitulos[1].versos[19] = _("Tua glória, ó Israel, foi morta sobre os teus altos! Como caíram os valorosos!");
    b->dados[SAMUEL2].capitulos[1].versos[20] = _("Não o noticieis em Gate, nem o publiqueis nas ruas de Asquelom; para que não se alegrem as filhas dos filisteus, para que não exultem as filhas dos incircuncisos.");
    b->dados[SAMUEL2].capitulos[1].versos[21] = _("Vós, montes de Gilboa, nem orvalho, nem chuva caia sobre, vós, ó campos de morte; pois ali desprezivelmente foi arrojado o escudo dos valorosos, o escudo de Saul, ungido com óleo.");
    b->dados[SAMUEL2].capitulos[1].versos[22] = _("Do sangue dos feridos, da gordura dos valorosos, nunca recuou o arco de Jônatas, nem voltou vazia a espada de Saul.");
    b->dados[SAMUEL2].capitulos[1].versos[23] = _("Saul e Jônatas, tão queridos e amáveis na sua vida, também na sua morte não se separaram; eram mais ligeiros do que as águias, mais fortes do que os leões.");
    b->dados[SAMUEL2].capitulos[1].versos[24] = _("Vós, filhas de Israel, chorai por Saul, que vos vestia deliciosamente de escarlata, que vos punha sobre os vestidos adornos de ouro.");
    b->dados[SAMUEL2].capitulos[1].versos[25] = _("Como caíram os valorosos no meio da peleja!");
    b->dados[SAMUEL2].capitulos[1].versos[26] = _("Angustiado estou por ti, meu irmão Jônatas; muito querido me eras! Maravilhoso me era o teu amor, ultrapassando o amor de mulheres.");
    b->dados[SAMUEL2].capitulos[1].versos[27] = _("Como caíram os valorosos, e pereceram as armas de guerra!");

    b->dados[SAMUEL2].capitulos[2].versos[1] = _("Sucedeu depois disto que Davi consultou ao Senhor, dizendo: Subirei a alguma das cidades de Judá? Respondeu-lhe o Senhor: Sobe. Ainda perguntou Davi: Para onde subirei? Respondeu o Senhor: Para Hebrom.");
    b->dados[SAMUEL2].capitulos[2].versos[2] = _("Subiu, pois, Davi para lá, e também as suas duas mulheres, Ainoã, a jizreelita, e Abigail, que fora mulher de Nabal, e carmelita.");
    b->dados[SAMUEL2].capitulos[2].versos[3] = _("Davi fez subir também os homens que estavam com ele, cada um com sua família; e habitaram nas cidades de Hebrom.");
    b->dados[SAMUEL2].capitulos[2].versos[4] = _("Então vieram os homens de Judá, e ali ungiram Davi rei sobre a casa de Judá. Depois informaram a Davi, dizendo: Foram os homens de Jabes-Gileade que sepultaram a Saul.");
    b->dados[SAMUEL2].capitulos[2].versos[5] = _("Pelo que Davi enviou mensageiros aos homens de Jabes-Gileade, a dizer-lhes: Benditos do Senhor sejais vós, que fizestes tal benevolência, sepultando a Saul, vosso senhor!");
    b->dados[SAMUEL2].capitulos[2].versos[6] = _("Agora, pois, o Senhor use convosco de benevolência e fidelidade; e eu também vos retribuirei esse bem que fizestes.");
    b->dados[SAMUEL2].capitulos[2].versos[7] = _("Esforcem-se, pois, agora as vossas mãos, e sede homens valorosos; porque Saul, vosso senhor, é morto, e a casa de Judá me ungiu por seu rei.");
    b->dados[SAMUEL2].capitulos[2].versos[8] = _("Ora, Abner, filho de Ner, chefe do exército de Saul, tomou a Is-Bosete, filho de Saul, e o fez passar a Maanaim,");
    b->dados[SAMUEL2].capitulos[2].versos[9] = _("e o constituiu rei sobre Gileade, sobre os asuritas, sobre Jizreel, sobre Efraim, sobre Benjamim e sobre todo o Israel.");
    b->dados[SAMUEL2].capitulos[2].versos[10] = _("Quarenta anos tinha Is-Bosete, filho de Saul, quando começou a reinar sobre Israel, e reinou dois anos, A casa de Judá, porém, seguia a Davi.");
    b->dados[SAMUEL2].capitulos[2].versos[11] = _("E foi o tempo que Davi reinou em Hebrom, sobre a casa de Judá, sete anos e seis meses.");
    b->dados[SAMUEL2].capitulos[2].versos[12] = _("Depois Abner, filho de Ner, com os servos de Is-Bosete, filho de Saul, saiu de Maanaim para Gibeão.");
    b->dados[SAMUEL2].capitulos[2].versos[13] = _("Saíram também Joabe, filho de Zeruia, e os servos de Davi, e se encontraram com eles perto do tanque de Gibeão; e pararam uns de um lado do tanque, e os outros do outro lado.");
    b->dados[SAMUEL2].capitulos[2].versos[14] = _("Então disse Abner a Joabe: Levantem-se os mancebos, e se batam diante de nós. Respondeu Joabe: Levantem-se.");
    b->dados[SAMUEL2].capitulos[2].versos[15] = _("Levantaram-se, pois, e passaram, em número de doze por Benjamim e por Is-Bosete, filho de Saul, e doze dos servos de Davi.");
    b->dados[SAMUEL2].capitulos[2].versos[16] = _("E cada um lançou mão da cabeça de seu contendor, e meteu-lhe a espada pela ilharga; assim caíram juntos; pelo que se chamou àquele lugar, que está junto a Gibeão, Helcate-Hazurim.");
    b->dados[SAMUEL2].capitulos[2].versos[17] = _("Seguiu-se naquele dia uma crua peleja; e Abner e os homens de Israel foram derrotados diante dos servos de Davi.");
    b->dados[SAMUEL2].capitulos[2].versos[18] = _("Ora, estavam ali os três filhos de Zeruia: Joabe, Abisai, e Asael; e Asael era ligeiro de pés, como as gazelas do campo.");
    b->dados[SAMUEL2].capitulos[2].versos[19] = _("Perseguiu, pois, Asael a Abner, seguindo-o sem se desviar nem para a direita nem para a esquerda.");
    b->dados[SAMUEL2].capitulos[2].versos[20] = _("Nisso Abner, olhando para trás, perguntou: És tu Asael? Respondeu ele: Sou eu.");
    b->dados[SAMUEL2].capitulos[2].versos[21] = _("Ao que lhe disse Abner: Desvia-te para a direita, ou para a esquerda, e lança mão de um dos mancebos, e toma os seus despojos. Asael, porém , não quis desviar-se de seguí-lo.");
    b->dados[SAMUEL2].capitulos[2].versos[22] = _("Então Abner tornou a dizer a Asael: Desvia-te de detrás de mim; porque hei de ferir-te e dar contigo em terra? e como levantaria eu o meu rosto diante de Joabe, teu irmão?");
    b->dados[SAMUEL2].capitulos[2].versos[23] = _("Todavia ele recusou desviar-se; pelo que Abner o feriu com o conto da lança pelo ventre, de modo que a lança lhe saiu por detrás; e ele caiu ali, e morreu naquele mesmo lugar. E sucedeu que, todos os que chegavam ao lugar onde Asael caíra morto, paravam.");
    b->dados[SAMUEL2].capitulos[2].versos[24] = _("Mas Joabe e Abisai perseguiram a Abner; e pôs-se o sol ao chegarem eles ao outeiro de Amá, que está diante de Giá, junto ao caminho do deserto de Gibeão.");
    b->dados[SAMUEL2].capitulos[2].versos[25] = _("E os filhos de Benjamim se ajuntaram atrás de Abner e, formando-se num batalhão, puseram-se no cume dum outeiro.");
    b->dados[SAMUEL2].capitulos[2].versos[26] = _("Então Abner gritou a Joabe, e disse: Devorará a espada para sempre? não sabes que por fim haverá amargura? até quando te demorarás em ordenar ao povo que deixe de perseguir a seus irmãos?");
    b->dados[SAMUEL2].capitulos[2].versos[27] = _("Respondeu Joabe: Vive Deus, que, se não tivesses falado, só amanhã cedo teria o povo cessado, cada um, de perseguir a seu irmão.");
    b->dados[SAMUEL2].capitulos[2].versos[28] = _("Então Joabe tocou a buzina, e todo o povo parou; e não perseguiram mais a Israel, e tampouco pelejaram mais.");
    b->dados[SAMUEL2].capitulos[2].versos[29] = _("E caminharam Abner e os seus homens toda aquela noite pela Arabá; e, passando o Jordão, caminharam por todo o Bitrom, e vieram a Maanaim.");
    b->dados[SAMUEL2].capitulos[2].versos[30] = _("Voltou, pois, Joabe de seguir a Abner; e quando ajuntou todo o povo, faltavam dos servos de Davi dezenove homens, e Asael.");
    b->dados[SAMUEL2].capitulos[2].versos[31] = _("Mas os servos de Davi tinham ferido dentre os de Benjamim, e dentre os homens de Abner, a trezentos e sessenta homens, de tal maneira que morreram.");
    b->dados[SAMUEL2].capitulos[2].versos[32] = _("E levantaram a Asael, e o sepultaram no sepulcro de seu pai, que estava em Belém. E Joabe e seus homens caminharam toda aquela noite, e amanheceu-lhes o dia em Hebrom.");

    b->dados[SAMUEL2].capitulos[3].versos[1] = _("Ora, houve uma longa guerra entre a casa de Saul e a casa de Davi; porém Davi se fortalecia cada vez mais, enquanto a casa de Saul cada vez mais se enfraquecia.");
    b->dados[SAMUEL2].capitulos[3].versos[2] = _("Nasceram filhos a Davi em Hebrom. Seu primogênito foi Amnom, de Ainoã, a jizreelita;");
    b->dados[SAMUEL2].capitulos[3].versos[3] = _("o segundo Quileabe, de Abigail, que fôra mulher de Nabal, o carmelita; o terceiro Absalão, filho de Maacá, filha de Talmai, rei de Gesur;");
    b->dados[SAMUEL2].capitulos[3].versos[4] = _("o quarto Adonias, filho de Hagite, o quinto Sefatias, filho de Abital;");
    b->dados[SAMUEL2].capitulos[3].versos[5] = _("e o sexto Itreão, de Eglá, também mulher de Davi; estes nasceram a Davi em Hebrom.");
    b->dados[SAMUEL2].capitulos[3].versos[6] = _("Enquanto havia guerra entre a casa de Saul e a casa de Davi, Abner ia se tornando poderoso na casa de Saul:");
    b->dados[SAMUEL2].capitulos[3].versos[7] = _("Ora, Saul tivera uma concubina, cujo nome era Rizpa, filha de Aías. Perguntou, pois, Is-Bosete a Abner: Por que entraste à concubina de meu pai?");
    b->dados[SAMUEL2].capitulos[3].versos[8] = _("Então Abner, irando-se muito pelas palavras de Is-Bosete, disse: Sou eu cabeça de cão, que pertença a Judá? Ainda hoje uso de benevolência para com a casa de Saul, teu pai, e para com seus irmãos e seus amigos, e não te entreguei nas mãos de Davi; contudo tu hoje queres culpar-me no tocante a essa mulher.");
    b->dados[SAMUEL2].capitulos[3].versos[9] = _("Assim faça Deus a Abner, e outro tanto, se, como o Senhor jurou a Davi, assim eu não lhe fizer,");
    b->dados[SAMUEL2].capitulos[3].versos[10] = _("transferindo o reino da casa de Saul, e estabelecendo o trono de Davi sobre Israel, e sobre Judá, desde Dã até Berseba.");
    b->dados[SAMUEL2].capitulos[3].versos[11] = _("E Is-Bosete não pôde responder a Abner mais uma palavra, porque o temia.");
    b->dados[SAMUEL2].capitulos[3].versos[12] = _("Então enviou Abner da sua parte mensageiros a Davi, dizendo: De quem é a terra? Comigo faze a tua aliança, e eis que a minha mão será contigo, para fazer tornar a ti todo o Israel.");
    b->dados[SAMUEL2].capitulos[3].versos[13] = _("Respondeu Davi: Está bem; farei aliança contigo; mas uma coisa te exijo; não verás a minha face, se primeiro não me trouxeres Mical, filha de Saul, quando vieres ver a minha face.");
    b->dados[SAMUEL2].capitulos[3].versos[14] = _("Também enviou Davi mensageiros a Is-Bosete, filho de Saul, dizendo: Entrega-me minha mulher Mical, que eu desposei por cem prepúcios de filisteus.");
    b->dados[SAMUEL2].capitulos[3].versos[15] = _("Enviou, pois, Is-Bosete, e a tirou a seu marido, a Paltiel, filho de Laís,");
    b->dados[SAMUEL2].capitulos[3].versos[16] = _("que a seguia, chorando atrás dela até Baurim. Então lhe disse Abner: Vai-te; volta! E ele voltou.");
    b->dados[SAMUEL2].capitulos[3].versos[17] = _("Falou Abner com os anciãos de Israel, dizendo: De há muito procurais fazer com que Davi reine sobre vós;");
    b->dados[SAMUEL2].capitulos[3].versos[18] = _("fazei-o, pois, agora, porque o Senhor falou de Davi, dizendo: Pela mão do meu servo Davi livrarei o meu povo da mão dos filisteus e da mão de todos os seus inimigos.");
    b->dados[SAMUEL2].capitulos[3].versos[19] = _("Do mesmo modo falou Abner a Benjamim, e foi também dizer a Davi, em Hebrom, tudo o que Israel e toda a casa de Benjamim tinham resolvido.");
    b->dados[SAMUEL2].capitulos[3].versos[20] = _("Abner foi ter com Davi, em Hebrom, com vinte homens; e Davi fez um banquete a Abner e aos homens que com ele estavam.");
    b->dados[SAMUEL2].capitulos[3].versos[21] = _("Então disse Abner a Davi: Eu me levantarei, e irei ajuntar ao rei meu senhor todo o Israel, para que faça aliança contigo; e tu reinarás sobre tudo o que desejar a sua alma: Assim despediu Davi a Abner, e ele se foi em paz.");
    b->dados[SAMUEL2].capitulos[3].versos[22] = _("Eis que os servos de Davi e Joabe voltaram de uma sortida, e traziam consigo grande despojo; mas Abner já não estava com Davi em Hebrom, porque este o tinha despedido, e ele se fora em paz.");
    b->dados[SAMUEL2].capitulos[3].versos[23] = _("Quando, pois, chegaram Joabe e todo o exército que vinha com ele, disseram-lhe: Abner, filho de Ner, veio ter com o rei; e o rei o despediu, e ele se foi em paz.");
    b->dados[SAMUEL2].capitulos[3].versos[24] = _("Então Joabe foi ao rei, e disse: Que fizeste? Eis que Abner veio ter contigo; por que, pois, o despediste, de maneira que se fosse assim livremente?");
    b->dados[SAMUEL2].capitulos[3].versos[25] = _("Bem conheces a Abner, filho de Ner; ele te veio enganar, e saber a tua saída e a tua entrada, e conhecer tudo quanto fazes.");
    b->dados[SAMUEL2].capitulos[3].versos[26] = _("E Joabe, retirando-se de Davi, enviou mensageiros atrás de Abner, que o fizeram voltar do poço de Sira, sem que Davi o soubesse.");
    b->dados[SAMUEL2].capitulos[3].versos[27] = _("Quando Abner voltou a Hebrom, Joabe o tomou à parte, à entrada da porta, para lhe falar em segredo; e ali, por causa do sangue de Asael, seu irmão, o feriu no ventre, de modo que ele morreu.");
    b->dados[SAMUEL2].capitulos[3].versos[28] = _("Depois Davi, quando o soube, disse: Inocente para sempre sou eu, e o meu reino, para com o Senhor, no tocante ao sangue de Abner, filho de Ner.");
    b->dados[SAMUEL2].capitulos[3].versos[29] = _("Caia ele sobre a cabeça de Joabe e sobre toda a casa de seu pai, e nunca falte na casa de Joabe quem tenha fluxo, ou quem seja leproso, ou quem se atenha a bordão, ou quem caia à espada, ou quem necessite de pão.");
    b->dados[SAMUEL2].capitulos[3].versos[30] = _("Joabe, pois, e Abisai, seu irmão, mataram Abner, por ter ele morto a Asael, irmão deles, na peleja em Gibeão.");
    b->dados[SAMUEL2].capitulos[3].versos[31] = _("Disse Davi a Joabe e a todo o povo que com ele estava: Rasgai as vossas vestes, cingi-vos de sacos e ide pranteando diante de Abner. E o rei Davi ia seguindo o féretro.");
    b->dados[SAMUEL2].capitulos[3].versos[32] = _("Sepultaram Abner em Hebrom; e o rei, levantando a sua voz, chorou junto da sepultura de Abner; chorou também todo o povo.");
    b->dados[SAMUEL2].capitulos[3].versos[33] = _("Pranteou o rei a Abner, dizendo: Devia Abner, porventura, morrer como morre o vilão?");
    b->dados[SAMUEL2].capitulos[3].versos[34] = _("As tuas mãos não estavam atadas, nem os teus pés carregados de grilhões; mas caíste como quem cai diante dos filhos da iniqüidade. Então todo o povo tornou a chorar por ele.");
    b->dados[SAMUEL2].capitulos[3].versos[35] = _("Depois todo o povo veio fazer com que Davi comesse pão, sendo ainda dia; porém Davi jurou, dizendo: Assim Deus me faça e outro tanto, se, antes que o sol se ponha, eu provar pão ou qualquer outra coisa.");
    b->dados[SAMUEL2].capitulos[3].versos[36] = _("Todo o povo notou isso, e pareceu-lhe bem; assim como tudo quanto o rei fez pareceu bem a todo o povo.");
    b->dados[SAMUEL2].capitulos[3].versos[37] = _("Assim todo o povo e todo o Israel entenderam naquele mesmo dia que não fora a vontade do rei que matassem a Abner, filho de Ner.");
    b->dados[SAMUEL2].capitulos[3].versos[38] = _("Então disse o rei aos seus servos: Não sabeis que hoje caiu em Israel um príncipe, um grande homem?");
    b->dados[SAMUEL2].capitulos[3].versos[39] = _("E quanto a mim, hoje estou fraco, embora ungido rei; estes homens, filhos de Zeruia, são duros demais para mim. Retribua o Senhor ao malfeitor conforme a sua maldade.");

    b->dados[SAMUEL2].capitulos[4].versos[1] = _("Quando Is-Bosete, filho de Saul, soube que Abner morrera em Hebrom, esvaíram-se-lhe as forças, e todo o Israel ficou perturbado.");
    b->dados[SAMUEL2].capitulos[4].versos[2] = _("Tinha Is-Bosete, filho de Saul, dois homens chefes de guerrilheiros; um deles se chamava Baaná, e o outro Recabe, filhos de Rimom, o beerotita, dos filhos de Benjamim {porque também Beerote era contado de Benjamim,");
    b->dados[SAMUEL2].capitulos[4].versos[3] = _("tendo os beerotitas fugido para Jitaim, onde têm peregrinado até o dia de hoje}.");
    b->dados[SAMUEL2].capitulos[4].versos[4] = _("Ora, Jônatas, filho de Saul, tinha um filho aleijado dos pés. Este era da idade de cinco anos quando chegaram de Jizreel as novas a respeito de Saul e Jônatas; pelo que sua ama o tomou, e fugiu; e sucedeu que, apressando-se ela a fugir, ele caiu, e ficou coxo. O seu nome era Mefibosete.");
    b->dados[SAMUEL2].capitulos[4].versos[5] = _("Foram os filhos de Rimom, o beerotita, Recabe e Baanã, no maior calor de dia, e entraram em casa de Is-Bosete, estando ele deitado a dormir a sesta.");
    b->dados[SAMUEL2].capitulos[4].versos[6] = _("Entraram ali até o meio da casa, como que vindo apanhar trigo, e o feriram no ventre; e Recabe e Baaná, seu irmão, escaparam.");
    b->dados[SAMUEL2].capitulos[4].versos[7] = _("Porque entraram na sua casa, estando ele deitado na cama, no seu quarto de dormir, e o feriram e mataram, e cortando-lhe a cabeça, tomaram-na e andaram a noite toda pelo caminho da Arabá.");
    b->dados[SAMUEL2].capitulos[4].versos[8] = _("Assim trouxeram a cabeça de Is-Bosete a Davi em Hebrom, e disseram ao rei: Eis aqui a cabeça de Is-Bosete, filho de Saul, teu inimigo, que procurava a tua morte; assim o Senhor vingou hoje ao rei meu Senhor, de Saul e da sua descendência.");
    b->dados[SAMUEL2].capitulos[4].versos[9] = _("Mas Davi, respondendo a Recabe e a Baaná, seu irmão, filhos de Rimom, e beerotita, disse-lhes: Vive o Senhor, que remiu a minha alma de toda a angústia!");
    b->dados[SAMUEL2].capitulos[4].versos[10] = _("Se àquele que me trouxe novas, dizendo: Eis que Saul é morto, cuidando que trazia boas novas, eu logo lancei mão dele, e o matei em Ziclague, sendo essa a recompensa que lhe dei pelas novas,");
    b->dados[SAMUEL2].capitulos[4].versos[11] = _("quanto mais quando homens cruéis mataram um homem justo em sua casa, sobre a sua cama, não requererei eu e seu sangue de vossas mãos, e não vos exterminarei da terra?");
    b->dados[SAMUEL2].capitulos[4].versos[12] = _("E Davi deu ordem aos seus mancebos; e eles os mataram e, cortando-lhes as mãos e os pés, os penduraram junto ao tanque em Hebrom. Tomaram, porém, a cabeça de Is-Bosete, e a sepultaram na sepultura de Abner, em Hebrom.");

    b->dados[SAMUEL2].capitulos[5].versos[1] = _("Então todas as tribos de Israel vieram a Davi em Hebrom e disseram: Eis-nos aqui, teus ossos e tua carne!");
    b->dados[SAMUEL2].capitulos[5].versos[2] = _("Além disso, outrora, quando Saul ainda reinava sobre nós, eras tu o que saías e entravas com Israel; e também o Senhor te disse: Tu apascentarás o meu povo de Israel, e tu serás chefe sobre Israel.");
    b->dados[SAMUEL2].capitulos[5].versos[3] = _("Assim, pois, todos os anciãos de Israel vieram ter com o rei em Hebrom; e o rei Davi fez aliança com eles em Hebrom, perante o Senhor; e ungiram a Davi rei sobre Israel.");
    b->dados[SAMUEL2].capitulos[5].versos[4] = _("Trinta anos tinha Davi quando começou a reinar, e reinou quarenta anos.");
    b->dados[SAMUEL2].capitulos[5].versos[5] = _("Em Hebrom reinou sete anos e seis meses sobre Judá, e em Jerusalém reinou trinta e três anos sobre todo o Israel e Judá.");
    b->dados[SAMUEL2].capitulos[5].versos[6] = _("Depois partiu o rei com os seus homens para Jerusalém, contra os jebuseus, que habitavam naquela terra, os quais disseram a Davi: Não entrarás aqui; os cegos e es coxos te repelirão; querendo dizer: Davi de maneira alguma entrará aqui.");
    b->dados[SAMUEL2].capitulos[5].versos[7] = _("Todavia Davi tomou a fortaleza de Sião; esta é a cidade de Davi.");
    b->dados[SAMUEL2].capitulos[5].versos[8] = _("Ora, Davi disse naquele dia: Todo o que ferir os jebuseus, suba ao canal, e fira a esses coxos e cegos, a quem a alma de Davi aborrece. Por isso se diz: Nem cego nem, coxo entrara na casa.");
    b->dados[SAMUEL2].capitulos[5].versos[9] = _("Assim habitou Davi na fortaleza, e chamou-a cidade de Davi; e foi levantando edifícios em redor, desde Milo para dentro.");
    b->dados[SAMUEL2].capitulos[5].versos[10] = _("Davi ia-se engrandecendo cada vez mais, porque o Senhor Deus dos exércitos era com ele.");
    b->dados[SAMUEL2].capitulos[5].versos[11] = _("Hirão, rei de Tiro, enviou mensageiros a Davi, e madeira de cedro, e carpinteiros e pedreiros, que edificaram para Davi uma casa.");
    b->dados[SAMUEL2].capitulos[5].versos[12] = _("Entendeu, pois, Davi que o Senhor o confirmara rei sobre Israel, e que exaltara e reino dele por amar do seu povo Israel.");
    b->dados[SAMUEL2].capitulos[5].versos[13] = _("Davi tomou ainda para si concubinas e mulheres de Jerusalém, depois que viera de Hebrom; e nasceram a Davi mais filhos e filhas.");
    b->dados[SAMUEL2].capitulos[5].versos[14] = _("São estes os nomes dos que lhe nasceram em Jerusalém: Samua, Sobabe, Natã, Salomão,");
    b->dados[SAMUEL2].capitulos[5].versos[15] = _("Ibar, Elisua, Nefegue, Jafia,");
    b->dados[SAMUEL2].capitulos[5].versos[16] = _("Elisama, e Eliadá e Elifelete.");
    b->dados[SAMUEL2].capitulos[5].versos[17] = _("Quando os filisteus ouviram que Davi fora ungido rei sobre Israel, subiram todos em busca dele. Ouvindo isto, Davi desceu à fortaleza.");
    b->dados[SAMUEL2].capitulos[5].versos[18] = _("Os filisteus vieram, e se estenderam pelo vale de Refaim.");
    b->dados[SAMUEL2].capitulos[5].versos[19] = _("Pelo que Davi consultou ao Senhor, dizendo: Subirei contra os filisteus? entregar-mos-ás nas mãos? Respondeu o Senhor a Davi: Sobe, pois eu entregarei os filisteus nas tuas mãos.");
    b->dados[SAMUEL2].capitulos[5].versos[20] = _("Então foi Davi a Baal-Perazim, e ali os derrotou; e disse: O Senhor rompeu os meus inimigos diante de mim, como as águas rompem barreiras. Por isso chamou o nome daquele lugar Baal-Perazim.");
    b->dados[SAMUEL2].capitulos[5].versos[21] = _("Os filisteus deixaram lá os seus ídolos, e Davi e os seus homens os levaram.");
    b->dados[SAMUEL2].capitulos[5].versos[22] = _("Tornaram ainda os filisteus a subir, e se espalharam pelo vale de Refaim.");
    b->dados[SAMUEL2].capitulos[5].versos[23] = _("E Davi consultou ao Senhor, que respondeu: Não subirás; mas rodeia-os por detrás, e virás sobre eles por defronte dos balsameiros.");
    b->dados[SAMUEL2].capitulos[5].versos[24] = _("E há de ser que, ouvindo tu o ruído de marcha pelas copas dos balsameiros, então te apressarás, porque é o Senhor que sai diante de ti, a ferir o arraial dos filisteus.");
    b->dados[SAMUEL2].capitulos[5].versos[25] = _("Fez, pois, Davi como o Senhor lhe havia ordenado; e feriu os filisteus desde Geba, até chegar a Gezer.");

    b->dados[SAMUEL2].capitulos[6].versos[1] = _("Tornou Davi a ajuntar todos os escolhidos de Israel, em número de trinta mil.");
    b->dados[SAMUEL2].capitulos[6].versos[2] = _("Depois levantou-se Davi, e partiu para Baal-Judá com todo o povo que tinha consigo, para trazerem dali para cima a arca de Deus, a qual é chamada pelo Nome, o nome do Senhor dos exércitos, que se assenta sobre os querubins.");
    b->dados[SAMUEL2].capitulos[6].versos[3] = _("Puseram a arca de Deus em um carro novo, e a levaram da casa de Abinadabe, que estava sobre o outeiro; e Uzá e Aiô, filhos de Abinadabe, guiavam o carro novo.");
    b->dados[SAMUEL2].capitulos[6].versos[4] = _("Foram, pois, levando-o da casa de Abinadabe, que estava sobre o outeiro, com a arca de Deus; e Aiô ia adiante da arca.");
    b->dados[SAMUEL2].capitulos[6].versos[5] = _("E Davi, e toda a casa de Israel, tocavam perante o Senhor, com toda sorte de instrumentos de pau de faia, como também com harpas, saltérios, tamboris, pandeiros e címbalos.");
    b->dados[SAMUEL2].capitulos[6].versos[6] = _("Quando chegaram à eira de Nacom, Uzá estendeu a mão à arca de Deus, e pegou nela, porque os bois tropeçaram.");
    b->dados[SAMUEL2].capitulos[6].versos[7] = _("Então a ira do Senhor se acendeu contra Uzá, e Deus o feriu ali; e Uzá morreu ali junto à arca de Deus.");
    b->dados[SAMUEL2].capitulos[6].versos[8] = _("E Davi se contristou, porque o Senhor abrira rotura em Uzá; e passou-se a chamar àquele lugar, Pérez-Uzá, até o dia de hoje.");
    b->dados[SAMUEL2].capitulos[6].versos[9] = _("Davi, pois, teve medo do Senhor naquele dia, e disse: Como virá a mim a arca do Senhor?");
    b->dados[SAMUEL2].capitulos[6].versos[10] = _("E não quis levar a arca do Senhor para a cidade de Davi; mas fê-la entrar na casa de Obede-Edom, o gitita.");
    b->dados[SAMUEL2].capitulos[6].versos[11] = _("E ficou a arca do Senhor três meses na casa de Obede-Edom, o gitita, e o Senhor o abençoou e a toda a sua casa.");
    b->dados[SAMUEL2].capitulos[6].versos[12] = _("Então informaram a Davi, dizendo: O Senhor abençoou a casa de Obede-Edom, e tudo quanto é dele, por causa da arca de Deus. Foi, pois, Davi, e com alegria fez subir a arca de Deus, da casa de Obede-Edom para a cidade de Davi.");
    b->dados[SAMUEL2].capitulos[6].versos[13] = _("Quando os que levavam a arca do Senhor tinham dado seis passos, ele sacrificou um boi e um animal cevado.");
    b->dados[SAMUEL2].capitulos[6].versos[14] = _("E Davi dançava com todas as suas forças diante do Senhor; e estava Davi cingido dum éfode de linho.");
    b->dados[SAMUEL2].capitulos[6].versos[15] = _("Assim Davi e toda a casa de Israel subiam, trazendo a arca do Senhor com júbilo e ao som de trombetas.");
    b->dados[SAMUEL2].capitulos[6].versos[16] = _("Quando entrava a arca do Senhor na cidade de Davi, Mical, filha de Saul, estava olhando pela janela; e, vendo ao rei Davi saltando e dançando diante do senhor, o desprezou no seu coração.");
    b->dados[SAMUEL2].capitulos[6].versos[17] = _("Introduziram, pois, a arca do Senhor, e a puseram no seu lugar, no meio da tenda que Davi lhe armara; e Davi ofereceu holocaustos e ofertas pacíficas perante o Senhor.");
    b->dados[SAMUEL2].capitulos[6].versos[18] = _("Quando Davi acabou de oferecer os holocaustos e ofertas pacíficas, abençoou o povo em nome do Senhor dos exércitos.");
    b->dados[SAMUEL2].capitulos[6].versos[19] = _("Depois repartiu a todo o povo, a toda a multidão de Israel, tanto a homens como a mulheres, a cada um, um bolo de pão, um bom pedaço de carne e um bolo de passas. Em seguida todo o povo se retirou, cada um para sua casa.");
    b->dados[SAMUEL2].capitulos[6].versos[20] = _("Então Davi voltou para abençoar a sua casa; e Mical, filha de Saul, saiu a encontrar-se com Davi, e disse: Quão honrado foi o rei de Israel, descobrindo-se hoje aos olhos das servas de seus servos, como sem pejo se descobre um indivíduo qualquer.");
    b->dados[SAMUEL2].capitulos[6].versos[21] = _("Disse, porém, Davi a Mical: Perante o Senhor, que teu escolheu a mim de preferência a teu pai e a toda a sua casa, estabelecendo-me por chefe sobre o povo do Senhor, sobre Israel, sim, foi perante Senhor que dancei; e perante ele ainda hei de dançar");
    b->dados[SAMUEL2].capitulos[6].versos[22] = _("Também ainda mais do que isso me envilecerei, e me humilharei aos meus olhos; mas das servas, de quem falaste, delas serei honrado.");
    b->dados[SAMUEL2].capitulos[6].versos[23] = _("E Mical, filha de Saul não teve filhos, até o dia de sua morte.");

    b->dados[SAMUEL2].capitulos[7].versos[1] = _("Ora, estando o rei Davi em sua casa e tendo-lhe dado o Senhor descanso de todos os seus inimigos em redor,");
    b->dados[SAMUEL2].capitulos[7].versos[2] = _("disse ele ao profeta Natã: Eis que eu moro numa casa de cedro, enquanto que a arca de Deus dentro de uma tenda.");
    b->dados[SAMUEL2].capitulos[7].versos[3] = _("Respondeu Natã ao rei: Vai e faze tudo quanto está no teu coração, porque o Senhor é contigo.");
    b->dados[SAMUEL2].capitulos[7].versos[4] = _("Mas naquela mesma noite a palavra do Senhor veio a Natã, dizendo:");
    b->dados[SAMUEL2].capitulos[7].versos[5] = _("Vai, e dize a meu servo Davi: Assim diz o Senhor: Edificar-me-ás tu uma casa para eu nela habitar?");
    b->dados[SAMUEL2].capitulos[7].versos[6] = _("Porque em casa nenhuma habitei, desde o dia em que fiz subir do Egito os filhos de Israel até o dia de hoje, mas tenho andado em tenda e em tabernáculo.");
    b->dados[SAMUEL2].capitulos[7].versos[7] = _("E em todo lugar em que tenho andado com todos os filhos de Israel, falei porventura, alguma palavra a qualquer das suas tribos a que mandei apascentar o meu povo de Israel, dizendo: por que não me edificais uma casa de cedro?");
    b->dados[SAMUEL2].capitulos[7].versos[8] = _("Agora, pois, assim dirás ao meu servo Davi: Assim diz o Senhor dos exércitos: Eu te tomei da malhada, de detrás das ovelhas, para que fosses príncipe sobre o meu povo, sobre Israel;");
    b->dados[SAMUEL2].capitulos[7].versos[9] = _("e fui contigo, por onde quer que foste, e destruí a todos os teus inimigos diante de ti; e te farei um grande nome, como o nome dos grandes que há na terra.");
    b->dados[SAMUEL2].capitulos[7].versos[10] = _("Também designarei lugar para o meu povo, para Israel, e o plantarei ali, para que ele habite no seu lugar, e não mais seja perturbado, e nunca mais os filhos da iniqüidade o aflijam, como dantes,");
    b->dados[SAMUEL2].capitulos[7].versos[11] = _("e como desde o dia em que ordenei que houvesse juízes sobre o meu povo Israel. A ti, porém, darei descanso de todos os teus inimigos. Também o Senhor te declara que ele te fará casa.");
    b->dados[SAMUEL2].capitulos[7].versos[12] = _("Quando teus dias forem completos, e vieres a dormir com teus pais, então farei levantar depois de ti um dentre a tua descendência, que sair das tuas entranhas, e estabelecerei o seu reino.");
    b->dados[SAMUEL2].capitulos[7].versos[13] = _("Este edificará uma casa ao meu nome, e eu estabelecerei para sempre o trono do seu reino.");
    b->dados[SAMUEL2].capitulos[7].versos[14] = _("Eu lhe serei pai, e ele me será filho. E, se vier a transgredir, castigá-lo-ei com vara de homens, e com açoites de filhos de homens;");
    b->dados[SAMUEL2].capitulos[7].versos[15] = _("mas não retirarei dele a minha benignidade como a retirei de Saul, a quem tirei de diante de ti.");
    b->dados[SAMUEL2].capitulos[7].versos[16] = _("A tua casa, porém, e o teu reino serão firmados para sempre diante de ti; teu trono será estabelecido para sempre.");
    b->dados[SAMUEL2].capitulos[7].versos[17] = _("Conforme todas estas palavras, e conforme toda esta visão, assim falou Natã a Davi.");
    b->dados[SAMUEL2].capitulos[7].versos[18] = _("Então entrou o rei Davi, e sentou-se perante o Senhor, e disse: Quem sou eu, Senhor Jeová, e que é a minha casa, para me teres trazido até aqui?");
    b->dados[SAMUEL2].capitulos[7].versos[19] = _("E isso ainda foi pouco aos teus olhos, Senhor Jeová, senão que também falaste da casa do teu servo para tempos distantes; e me tens mostrado gerações futuras, ó Senhor Jeová?");
    b->dados[SAMUEL2].capitulos[7].versos[20] = _("Que mais te poderá dizer Davi. pois tu conheces bem o teu servo, ó Senhor Jeová.");
    b->dados[SAMUEL2].capitulos[7].versos[21] = _("Por causa da tua palavra, e segundo o teu coração, fizeste toda esta grandeza, revelando-a ao teu servo.");
    b->dados[SAMUEL2].capitulos[7].versos[22] = _("Portanto és grandioso, ó Senhor Jeová, porque ninguém há semelhante a ti, e não há Deus senão tu só, segundo tudo o que temos ouvido com os nossos ouvidos.");
    b->dados[SAMUEL2].capitulos[7].versos[23] = _("Que outra nação na terra é semelhante a teu povo Israel, a quem tu, ó Deus, foste resgatar para te ser povo, para te fazeres um nome, e para fazeres a seu favor estas grandes e terríveis coisas para a tua terra, diante do teu povo, que tu resgataste para ti do Egito, desterrando nações e seus deuses?");
    b->dados[SAMUEL2].capitulos[7].versos[24] = _("Assim estabeleceste o teu povo Israel por teu povo para sempre, e tu, Senhor, te fizeste o seu Deus.");
    b->dados[SAMUEL2].capitulos[7].versos[25] = _("Agora, pois, o Senhor Jeová, confirma para sempre a palavra que falaste acerca do teu servo e acerca da sua casa, e faze como tens falado,");
    b->dados[SAMUEL2].capitulos[7].versos[26] = _("para que seja engrandecido o teu nome para sempre, e se diga: O Senhor dos exércitos é Deus sobre Israel; e a casa do teu servo será estabelecida diante de ti.");
    b->dados[SAMUEL2].capitulos[7].versos[27] = _("Pois tu, Senhor dos exércitos, Deus de Israel, fizeste uma revelação ao teu servo, dizendo: Edificar-te-ei uma casa. Por isso o teu servo se animou a fazer-te esta oração.");
    b->dados[SAMUEL2].capitulos[7].versos[28] = _("Agora, pois, Senhor Jeová, tu és Deus, e as tuas palavras são verdade, e tens prometido a teu servo este bem.");
    b->dados[SAMUEL2].capitulos[7].versos[29] = _("Sê, pois, agora servido de abençoar a casa do teu servo, para que subsista para sempre diante de ti; pois tu, ó Senhor Jeová, o disseste; e com a tua bênção a casa do teu servo será, abençoada para sempre.");

    b->dados[SAMUEL2].capitulos[8].versos[1] = _("Sucedeu depois disso que Davi derrotou os filisteus, e os sujeitou; e Davi tomou a Metegue-Ama das mãos dos filisteus.");
    b->dados[SAMUEL2].capitulos[8].versos[2] = _("Também derrotou os moabitas, e os mediu com cordel, fazendo-os deitar por terra; e mediu dois cordéis para os matar, e um cordel inteiro para os deixar com vida. Ficaram assim os moabitas por servos de Davi, pagando-lhe tributos.");
    b->dados[SAMUEL2].capitulos[8].versos[3] = _("Davi também derrotou a Hadadézer, filho de Reobe, rei de Zobá, quando este ia estabelecer o seu domínio sobre o rio Eufrates.");
    b->dados[SAMUEL2].capitulos[8].versos[4] = _("E tomou-lhe Davi mil e setecentos cavaleiros e vinte mil homens de infantaria; e Davi jarretou a todos os cavalos dos carros, reservando apenas cavalos para cem carros.");
    b->dados[SAMUEL2].capitulos[8].versos[5] = _("Os sírios de Damasco vieram socorrer a Hadadézer, rei de Zobá, mas Davi matou deles vinte e dois mil homens.");
    b->dados[SAMUEL2].capitulos[8].versos[6] = _("Então Davi pôs guarnições em Síria de Damasco, e os sírios ficaram por servos de Davi, pagando-lhe tributos. E o Senhor lhe dava a vitória por onde quer que ia.");
    b->dados[SAMUEL2].capitulos[8].versos[7] = _("E Davi tomou os escudos de ouro que os servos de Hadadézer usavam, e os trouxe para Jerusalém.");
    b->dados[SAMUEL2].capitulos[8].versos[8] = _("De Betá e de Berotai, cidades de Hadadézer, o rei Davi tomou grande quantidade de bronze.");
    b->dados[SAMUEL2].capitulos[8].versos[9] = _("Quando Toí, rei de Hamate, ouviu que Davi ferira todo o exército de Hadadézer,");
    b->dados[SAMUEL2].capitulos[8].versos[10] = _("mandou-lhe seu filho Jorão para saudá-lo, e para felicitá-lo por haver pelejado contra Hadadézer e o haver derrotado; pois Hadadézer de contínuo fazia guerra a Toí. E Jorão trouxe consigo vasos de prata de ouro e de bronze,");
    b->dados[SAMUEL2].capitulos[8].versos[11] = _("os quais o rei Davi consagrou ao Senhor, como já havia consagrado a prata e o ouro de todas as nações que sujeitara.");
    b->dados[SAMUEL2].capitulos[8].versos[12] = _("da Síria, de Moabe, dos amonitas, dos filisteus, de Amaleque e dos despojos de Hadadézer, filho de Reobe, rei de Zobá.");
    b->dados[SAMUEL2].capitulos[8].versos[13] = _("Assim Davi ganhou nome para si. E quando voltou, matou no Vale do Sal a dezoito mil edomitas.");
    b->dados[SAMUEL2].capitulos[8].versos[14] = _("E pôs guarnições em Edom; pô-las em todo o Edom, e todos os edomitas tornaram-se servos de Davi. E o Senhor lhe dava a vitória por onde quer que ia.");
    b->dados[SAMUEL2].capitulos[8].versos[15] = _("Reinou, pois, Davi sobre todo o Israel, e administrava a justiça e a eqüidade a todo o seu povo.");
    b->dados[SAMUEL2].capitulos[8].versos[16] = _("Joabe, filho de Zeruia, estava sobre o exército; Jeosafá, filho de Ailude, era cronista;");
    b->dados[SAMUEL2].capitulos[8].versos[17] = _("Zadoque, filho de Aitube, e Aimeleque, filho de Abiatar, eram sacerdotes; Seraías era escrivão;");
    b->dados[SAMUEL2].capitulos[8].versos[18] = _("Benaías, filho de Jeoiada, tinha o cargo dos quereteus e peleteus; e os filhos de Davi eram ministros de estado.");

    b->dados[SAMUEL2].capitulos[9].versos[1] = _("Disse Davi: Resta ainda alguém da casa de Saul, para que eu use de benevolência para com ele por amor de Jônatas?");
    b->dados[SAMUEL2].capitulos[9].versos[2] = _("E havia um servo da casa de Saul, cujo nome era Ziba; e o chamaram à presença de Davi. perguntou-lhe o rei: Tu és Ziba? Respondeu ele: Teu servo!");
    b->dados[SAMUEL2].capitulos[9].versos[3] = _("Prosseguiu o rei: Não há ainda alguém da casa de Saul para que eu possa usar com ele da benevolência de Deus? Então disse Ziba ao rei: Ainda há um filho de Jônatas, aleijado dos pés.");
    b->dados[SAMUEL2].capitulos[9].versos[4] = _("Perguntou-lhe o rei: Onde está. Respondeu Ziba ao rei: Está em casa de Maquir, filho de Amiel, em Lo-Debar.");
    b->dados[SAMUEL2].capitulos[9].versos[5] = _("Então mandou o rei Davi, e o tomou da casa de Maquir, filho de Amiel, em Lo-Debar.");
    b->dados[SAMUEL2].capitulos[9].versos[6] = _("E Mefibosete, filho de Jônatas, filho de Saul, veio a Davi e, prostrando-se com o rosto em terra, lhe fez reverência. E disse Davi: Mefibosete! Respondeu ele: Eis aqui teu servo.");
    b->dados[SAMUEL2].capitulos[9].versos[7] = _("Então lhe disse Davi: Não temas, porque de certo usarei contigo de benevolência por amor de Jônatas, teu pai, e te restituirei todas as terras de Saul, teu pai; e tu sempre comerás à minha mesa.");
    b->dados[SAMUEL2].capitulos[9].versos[8] = _("Então Mefibosete lhe fez reverência, e disse: Que é o teu servo, para teres olhado para um cão morto tal como eu?");
    b->dados[SAMUEL2].capitulos[9].versos[9] = _("Então chamou Davi a Ziba, servo de Saul, e disse-lhe: Tudo o que pertencia a Saul, e a toda a sua casa, tenho dado ao filho de teu senhor.");
    b->dados[SAMUEL2].capitulos[9].versos[10] = _("Cultivar-lhe-ás, pois, a terra, tu e teus filhos, e teus servos; e recolherás os frutos, para que o filho de teu senhor tenha pão para comer; mas Mefibosete, filho de teu senhor, comerá sempre à minha mesa. Ora, tinha Ziba quinze filhos e vinte servos.");
    b->dados[SAMUEL2].capitulos[9].versos[11] = _("Respondeu Ziba ao rei: Conforme tudo quanto meu senhor, o rei, manda a seu servo, assim o fará ele. Disse o rei: Quanto a Mefibosete, ele comerá à minha mesa como um dos filhos do rei.");
    b->dados[SAMUEL2].capitulos[9].versos[12] = _("E tinha Mefibosete um filho pequeno, cujo nome era Mica. E todos quantos moravam em casa de Ziba eram servos de Mefibosete.");
    b->dados[SAMUEL2].capitulos[9].versos[13] = _("Morava, pois, Mefibosete em Jerusalém, porquanto sempre comia à mesa do rei. E era coxo de ambos os pés.");

    b->dados[SAMUEL2].capitulos[10].versos[1] = _("Depois disto morreu o rei dos amonitas, e seu filho Hanum reinou em seu lugar.");
    b->dados[SAMUEL2].capitulos[10].versos[2] = _("Então disse Davi: usarei de benevolência para com Hanum, filho de Naás, como seu pai usou de benevolência para comigo. Davi, pois, enviou os seus servos para o consolar acerca de seu pai; e foram os servos de Davi à terra dos amonitas.");
    b->dados[SAMUEL2].capitulos[10].versos[3] = _("Então disseram os príncipes dos amonitas a seu senhor, Hanum: Pensas, porventura, que foi para honrar teu pai que Davi te enviou consoladores? Não te enviou antes os seus servos para reconhecerem esta cidade e para a espiarem, a fim de transtorná-la?");
    b->dados[SAMUEL2].capitulos[10].versos[4] = _("Pelo que Hanum tomou os servos de Davi, rapou-lhes metade da barba, cortou-lhes metade dos vestidos, até as nádegas, e os despediu.");
    b->dados[SAMUEL2].capitulos[10].versos[5] = _("Quando isso foi dito a Davi, enviou ele mensageiros a encontrá-los, porque aqueles homens estavam sobremaneira envergonhados; e mandou dizer-lhes: Deixai-vos estar em Jericó, até que vos torne a crescer a barba, e então voltai.");
    b->dados[SAMUEL2].capitulos[10].versos[6] = _("Vendo, pois, os amonitas que se haviam feito abomináveis para com Davi, enviaram e alugaram dos sírios de Bete-Reobe e dos sírios de Bete-Reobe e dos sírios de Sobá vinte mil homens de infantaria, e do rei de Maacá mil homens, e dos homens de Tobe doze mil.");
    b->dados[SAMUEL2].capitulos[10].versos[7] = _("O que ouvindo Davi, enviou contra eles a Joabe com todo o exército dos valentes.");
    b->dados[SAMUEL2].capitulos[10].versos[8] = _("E saíram os amonitas, e ordenaram a batalha a entrada da porta; mas os sírios de Zobá e de Reobe, e os homens de Tobe e de Maacá estavam à parte no campo.");
    b->dados[SAMUEL2].capitulos[10].versos[9] = _("Vendo, pois, Joabe que a batalha estava preparada contra ele pela frente e pela retaguarda, escolheu alguns homens dentre a flor do exército de Israel, e formou-os em linha contra os sírios;");
    b->dados[SAMUEL2].capitulos[10].versos[10] = _("e entregou o resto do povo a seu irmão Abisai, para que o formasse em linha contra os amonitas.");
    b->dados[SAMUEL2].capitulos[10].versos[11] = _("E disse-lhe: Se os sírios forem mais fortes do que eu, tu me virás em socorro; e se os amonitas forem mais fortes do que tu, eu irei em teu socorro.");
    b->dados[SAMUEL2].capitulos[10].versos[12] = _("Tem bom ânimo, e sejamos corajosos pelo nosso povo, e pelas cidades de nosso Deus; e faça o Senhor o que bem lhe parecer.");
    b->dados[SAMUEL2].capitulos[10].versos[13] = _("Então Joabe e o povo que estava com ele travaram a peleja contra os sírios; e estes fugiram diante dele.");
    b->dados[SAMUEL2].capitulos[10].versos[14] = _("E, vendo os amonitas que os sírios fugiam, também eles fugiram de diante de Abisai, e entraram na cidade. Então Joabe voltou dos amonitas e veio para Jerusalém.");
    b->dados[SAMUEL2].capitulos[10].versos[15] = _("Os sírios, vendo que tinham sido derrotados diante de Israel, trataram de refazer-se.");
    b->dados[SAMUEL2].capitulos[10].versos[16] = _("E Hadadézer mandou que viessem os sírios que estavam da outra banda do rio; e eles vieram a Helã, tendo à sua frente Sobaque, chefe do exército de Hadadézer.");
    b->dados[SAMUEL2].capitulos[10].versos[17] = _("Davi, informado disto, ajuntou todo o Israel e, passando o Jordão, foi a Helã; e os sírios se puseram em ordem contra Davi, e pelejaram contra ele.");
    b->dados[SAMUEL2].capitulos[10].versos[18] = _("Os sírios, porém, fugiram de diante de Israel; e Davi matou deles os homens de setecentos carros, e quarenta mil homens de cavalaria; e feriu a Sobaque, general do exército, de sorte que ele morreu ali.");
    b->dados[SAMUEL2].capitulos[10].versos[19] = _("Vendo, pois, todos os reis, servos de Hadadézer, que estavam derrotados diante de Israel, fizeram paz com Israel, e o serviram. E os sírios não ousaram mais socorrer aos amonitas.");

    b->dados[SAMUEL2].capitulos[11].versos[1] = _("Tendo decorrido um ano, no tempo em que os reis saem à guerra, Davi enviou Joabe, e com ele os seus servos e todo o Israel; e eles destruíram os amonitas, e sitiaram a Rabá. Porém Davi ficou em Jerusalém.");
    b->dados[SAMUEL2].capitulos[11].versos[2] = _("Ora, aconteceu que, numa tarde, Davi se levantou do seu leito e se pôs a passear no terraço da casa real; e do terraço viu uma mulher que se estava lavando; e era esta mulher mui formosa à vista.");
    b->dados[SAMUEL2].capitulos[11].versos[3] = _("Tendo Davi enviado a indagar a respeito daquela mulher, disseram-lhe: Porventura não é Bate-Seba, filha de Eliã, mulher de Urias, o heteu?");
    b->dados[SAMUEL2].capitulos[11].versos[4] = _("Então Davi mandou mensageiros para trazê-la; e ela veio a ele, e ele se deitou com ela {pois já estava purificada da sua imundícia}; depois ela voltou para sua casa.");
    b->dados[SAMUEL2].capitulos[11].versos[5] = _("A mulher concebeu; e mandou dizer a Davi: Estou grávida.");
    b->dados[SAMUEL2].capitulos[11].versos[6] = _("Então Davi mandou dizer a Joabe: Envia-me Urias, o heteu. E Joabe o enviou a Davi.");
    b->dados[SAMUEL2].capitulos[11].versos[7] = _("Vindo, pois, Urias a Davi, este lhe perguntou como passava Joabe, e como estava o povo, e como ia a guerra.");
    b->dados[SAMUEL2].capitulos[11].versos[8] = _("Depois disse Davi a Urias: Desce a tua casa, e lava os teus pés. E, saindo Urias da casa real, logo foi mandado após ele um presente do rei.");
    b->dados[SAMUEL2].capitulos[11].versos[9] = _("Mas Urias dormiu à porta da casa real, com todos os servos do seu senhor, e não desceu a sua casa.");
    b->dados[SAMUEL2].capitulos[11].versos[10] = _("E o contaram a Davi, dizendo: Urias não desceu a sua casa. Então perguntou Davi a Urias: Não vens tu duma jornada? por que não desceste a tua casa?");
    b->dados[SAMUEL2].capitulos[11].versos[11] = _("Respondeu Urias a Davi: A arca, e Israel, e Judá estão em tendas; e Joabe, meu senhor, e os servos de meu senhor estão acampados ao relento; e entrarei eu na minha casa, para comer e beber, e para me deitar com minha mulher? Como vives tu, e como vive a tua alma, não farei tal coisa.");
    b->dados[SAMUEL2].capitulos[11].versos[12] = _("Então disse Davi a Urias: Fica ainda hoje aqui, e amanhã te despedirei. Urias, pois, ficou em Jerusalém aquele dia e o seguinte.");
    b->dados[SAMUEL2].capitulos[11].versos[13] = _("E Davi o convidou a comer e a beber na sua presença, e o embebedou; e à tarde saiu Urias a deitar-se na sua cama com os servos de seu senhor, porém não desceu a sua casa.");
    b->dados[SAMUEL2].capitulos[11].versos[14] = _("Pela manhã Davi escreveu uma carta a Joabe, e mandou-lha por mão de Urias.");
    b->dados[SAMUEL2].capitulos[11].versos[15] = _("Escreveu na carta: Ponde Urias na frente onde for mais renhida a peleja, e retirai-vos dele, para que seja ferido e morra.");
    b->dados[SAMUEL2].capitulos[11].versos[16] = _("Enquanto Joabe sitiava a cidade, pôs Urias no lugar onde sabia que havia homens valentes.");
    b->dados[SAMUEL2].capitulos[11].versos[17] = _("Quando os homens da cidade saíram e pelejaram contra Joabe, caíram alguns do povo, isto é, dos servos de Davi; morreu também Urias, o heteu.");
    b->dados[SAMUEL2].capitulos[11].versos[18] = _("Então Joabe mandou dizer a Davi tudo o que sucedera na peleja;");
    b->dados[SAMUEL2].capitulos[11].versos[19] = _("e deu ordem ao mensageiro, dizendo: Quando tiveres acabado de contar ao rei tudo o que sucedeu nesta peleja,");
    b->dados[SAMUEL2].capitulos[11].versos[20] = _("caso o rei se encolerize, e te diga: Por que vos chegastes tão perto da cidade a pelejar. Não sabíeis vós que haviam de atirar do muro?");
    b->dados[SAMUEL2].capitulos[11].versos[21] = _("Quem matou a Abimeleque, filho de Jerubesete? Não foi uma mulher que lançou sobre ele, do alto do muro, a pedra superior dum moinho, de modo que morreu em Tebez? Por que chegastes tão perto do muro? Então dirás: Também morreu teu servo Urias, o heteu.");
    b->dados[SAMUEL2].capitulos[11].versos[22] = _("Partiu, pois, o mensageiro e, tendo chegado, referiu a Davi tudo o que Joabe lhe ordenara.");
    b->dados[SAMUEL2].capitulos[11].versos[23] = _("Disse o mensageiro a Davi: Os homens ganharam uma vantagem sobre nós, e sairam contra nos ao campo; porém nos os repelimos até a entrada da porta.");
    b->dados[SAMUEL2].capitulos[11].versos[24] = _("Então os flecheiros atiraram contra os teus servos desde o alto do muro, e morreram alguns servos do rei; e também morreu o teu servo Urias, o heteu.");
    b->dados[SAMUEL2].capitulos[11].versos[25] = _("Disse Davi ao mensageiro: Assim dirás a Joabe: Não te preocupes com isso, pois a espada tanto devora este como aquele; aperta a tua peleja contra a cidade, e a derrota. Encoraja-o tu assim.");
    b->dados[SAMUEL2].capitulos[11].versos[26] = _("Ouvindo, pois, a mulher de Urias que seu marido era morto, o chorou.");
    b->dados[SAMUEL2].capitulos[11].versos[27] = _("E, passado o tempo do luto, mandou Davi recolhê-la a sua casa: e ela lhe foi por mulher, e lhe deu um filho. Mas isto que Davi fez desagradou ao Senhor.");

    b->dados[SAMUEL2].capitulos[12].versos[1] = _("O Senhor, pois, enviou Natã a Davi. E, entrando ele a ter com Davi, disse-lhe: Havia numa cidade dois homens, um rico e outro pobre.");
    b->dados[SAMUEL2].capitulos[12].versos[2] = _("O rico tinha rebanhos e manadas em grande número;");
    b->dados[SAMUEL2].capitulos[12].versos[3] = _("mas o pobre não tinha coisa alguma, senão uma pequena cordeira que comprara e criara; ela crescera em companhia dele e de seus filhos; do seu bocado comia, do seu copo bebia, e dormia em seu regaço; e ele a tinha como filha.");
    b->dados[SAMUEL2].capitulos[12].versos[4] = _("Chegou um viajante à casa do rico; e este, não querendo tomar das suas ovelhas e do seu gado para guisar para o viajante que viera a ele, tomou a cordeira do pobre e a preparou para o seu hóspede.");
    b->dados[SAMUEL2].capitulos[12].versos[5] = _("Então a ira de Davi se acendeu em grande maneira contra aquele homem; e disse a Natã: Vive o Senhor, que digno de morte é o homem que fez isso.");
    b->dados[SAMUEL2].capitulos[12].versos[6] = _("Pela cordeira restituirá o quádruplo, porque fez tal coisa, e não teve compaixão.");
    b->dados[SAMUEL2].capitulos[12].versos[7] = _("Então disse Natã a Davi: Esse homem és tu! Assim diz o Senhor Deus de Israel: Eu te ungi rei sobre Israel, livrei-te da mão de Saul,");
    b->dados[SAMUEL2].capitulos[12].versos[8] = _("e te dei a casa de teu senhor, e as mulheres de teu senhor em teu seio; também te dei a casa de Israel e de Judá. E se isso fosse pouco, te acrescentaria outro tanto.");
    b->dados[SAMUEL2].capitulos[12].versos[9] = _("Por que desprezaste a palavra do Senhor, fazendo o mal diante de seus olhos? A Urias, o heteu, mataste à espada, e a sua mulher tomaste para ser tua mulher; sim, a ele mataste com a espada dos amonitas.");
    b->dados[SAMUEL2].capitulos[12].versos[10] = _("Agora, pois, a espada jamais se apartará da tua casa, porquanto me desprezaste, e tomaste a mulher de Urias, o heteu, para ser tua mulher.");
    b->dados[SAMUEL2].capitulos[12].versos[11] = _("Assim diz o Senhor: Eis que suscitarei da tua própria casa o mal sobre ti, e tomarei tuas mulheres perante os teus olhos, e as darei a teu próximo, o qual se deitará com tuas mulheres à luz deste sol.");
    b->dados[SAMUEL2].capitulos[12].versos[12] = _("Pois tu o fizeste em oculto; mas eu farei este negócio perante todo o Israel e à luz do sol.");
    b->dados[SAMUEL2].capitulos[12].versos[13] = _("Então disse Davi a Natã: Pequei contra o Senhor. Tornou Natã a Davi: Também o Senhor perdoou o teu pecado; não morreras.");
    b->dados[SAMUEL2].capitulos[12].versos[14] = _("Todavia, porquanto com este feito deste lugar a que os inimigos do Senhor blasfemem, o filho que te nasceu certamente morrerá.");
    b->dados[SAMUEL2].capitulos[12].versos[15] = _("Então Natã foi para sua casa. Depois o Senhor feriu a criança que a mulher de Urias dera a Davi, de sorte que adoeceu gravemente.");
    b->dados[SAMUEL2].capitulos[12].versos[16] = _("Davi, pois, buscou a Deus pela criança, e observou rigoroso jejum e, recolhendo-se, passava a noite toda prostrado sobre a terra.");
    b->dados[SAMUEL2].capitulos[12].versos[17] = _("Então os anciãos da sua casa se puseram ao lado dele para o fazerem levantar-se da terra; porém ele não quis, nem comeu com eles.");
    b->dados[SAMUEL2].capitulos[12].versos[18] = _("Ao sétimo dia a criança morreu; e temiam os servos de Davi dizer-lhe que a criança tinha morrido; pois diziam: Eis que, sendo a criança ainda viva, lhe falávamos, porém ele não dava ouvidos à nossa voz; como, pois, lhe diremos que a criança morreu? Poderá cometer um desatino.");
    b->dados[SAMUEL2].capitulos[12].versos[19] = _("Davi, porém, percebeu que seus servos cochichavam entre si, e entendeu que a criança havia morrido; pelo que perguntou a seus servos: Morreu a criança? E eles responderam: Morreu.");
    b->dados[SAMUEL2].capitulos[12].versos[20] = _("Então Davi se levantou da terra, lavou-se, ungiu-se, e mudou de vestes; e, entrando na casa do Senhor, adorou. Depois veio a sua casa, e pediu o que comer; e lho deram, e ele comeu.");
    b->dados[SAMUEL2].capitulos[12].versos[21] = _("Então os seus servos lhe disseram: Que é isso que fizeste? pela criança viva jejuaste e choraste; porém depois que a criança morreu te levantaste e comeste.");
    b->dados[SAMUEL2].capitulos[12].versos[22] = _("Respondeu ele: Quando a criança ainda vivia, jejuei e chorei, pois dizia: Quem sabe se o Senhor não se compadecerá de mim, de modo que viva a criança?");
    b->dados[SAMUEL2].capitulos[12].versos[23] = _("Todavia, agora que é morta, por que ainda jejuaria eu? Poderei eu fazê-la voltar? Eu irei para ela, porém ela não voltará para mim.");
    b->dados[SAMUEL2].capitulos[12].versos[24] = _("Então consolou Davi a Bate-Seba, sua mulher, e entrou, e se deitou com ela. E teve ela um filho, e Davi lhe deu o nome de Salomão. E o Senhor o amou;");
    b->dados[SAMUEL2].capitulos[12].versos[25] = _("e mandou, por intermédio do profeta Natã, dar-lhe o nome de Jedidias, por amor do Senhor.");
    b->dados[SAMUEL2].capitulos[12].versos[26] = _("Ora, pelejou Joabe contra Rabá, dos amonitas, e tomou a cidade real.");
    b->dados[SAMUEL2].capitulos[12].versos[27] = _("Então mandou Joabe mensageiros a Davi, e disse: Pelejei contra Rabá, e já tomei a cidade das águas.");
    b->dados[SAMUEL2].capitulos[12].versos[28] = _("Ajunta, pois, agora o resto do povo, acampa contra a cidade e toma-a, para que eu não a tome e seja o meu nome aclamado sobre ela.");
    b->dados[SAMUEL2].capitulos[12].versos[29] = _("Então Davi ajuntou todo o povo, e marchou para Rabá; pelejou contra ela, e a tomou.");
    b->dados[SAMUEL2].capitulos[12].versos[30] = _("Também tirou a coroa da cabeça do seu rei; e o peso dela era de um talento de ouro e havia nela uma pedra preciosa; e foi posta sobre a cabeça de Davi, que levou da cidade mui grande despojo.");
    b->dados[SAMUEL2].capitulos[12].versos[31] = _("E, trazendo os seus habitantes, os pôs a trabalhar com serras, trilhos de ferro, machados de ferro, e em fornos de tijolos; e assim fez a todas as cidades dos amonitas. Depois voltou Davi e todo o povo para Jerusalém.");

    b->dados[SAMUEL2].capitulos[13].versos[1] = _("Ora, Absalão, filho de Davi, tinha uma irmã formosa, cujo nome era Tamar; e sucedeu depois de algum tempo que Amnom, filho de Davi enamorou-se dela.");
    b->dados[SAMUEL2].capitulos[13].versos[2] = _("E angustiou-se Amnom, até adoecer, por amar, sua irmã; pois era virgem, e parecia impossível a Amnom fazer coisa alguma com ela.");
    b->dados[SAMUEL2].capitulos[13].versos[3] = _("Tinha, porém, Amnom um amigo, cujo nome era Jonadabe, filho de Siméia, irmão de Davi; e era Jonadabe homem mui sagaz.");
    b->dados[SAMUEL2].capitulos[13].versos[4] = _("Este lhe perguntou: Por que tu de dia para dia tanto emagreces, ó filho do rei? não mo dirás a mim? Então lhe respondeu Amnom: Amo a Tamar, irmã de Absalão, meu irmão.");
    b->dados[SAMUEL2].capitulos[13].versos[5] = _("Tornou-lhe Jonadabe: Deita-te na tua cama, e finge-te doente; e quando teu pai te vier visitar, dize-lhe: Peço-te que minha irmã Tamar venha dar-me de comer, preparando a comida diante dos meus olhos, para que eu veja e coma da sua mão.");
    b->dados[SAMUEL2].capitulos[13].versos[6] = _("Deitou-se, pois, Amnom, e fingiu-se doente. Vindo o rei visitá-lo, disse-lhe Amnom: Peço-te que minha irmã Tamar venha e prepare dois bolos diante dos meus olhos, para que eu coma da sua mão.");
    b->dados[SAMUEL2].capitulos[13].versos[7] = _("Mandou, então, Davi a casa, a dizer a Tamar: Vai a casa de Amnom, teu irmão, e faze-lhe alguma comida.");
    b->dados[SAMUEL2].capitulos[13].versos[8] = _("Foi, pois, Tamar a casa de Amnom, seu irmão; e ele estava deitado. Ela tomou massa e, amassando-a, fez bolos e os cozeu diante dos seus olhos.");
    b->dados[SAMUEL2].capitulos[13].versos[9] = _("E tomou a panela, e os tirou diante dele; porém ele recusou comer. E disse Amnom: Fazei retirar a todos da minha presença. E todos se retiraram dele.");
    b->dados[SAMUEL2].capitulos[13].versos[10] = _("Então disse Amnom a Tamar: Traze a comida a câmara, para que eu coma da tua mão. E Tamar, tomando os bolos que fizera, levou-os à câmara, ao seu irmão Amnom.");
    b->dados[SAMUEL2].capitulos[13].versos[11] = _("Quando lhos chegou, para que ele comesse, Amnom pegou dela, e disse-lhe: Vem, deita-te comigo, minha irmã.");
    b->dados[SAMUEL2].capitulos[13].versos[12] = _("Ela, porém, lhe respondeu: Não, meu irmão, não me forces, porque não se faz assim em Israel; não faças tal loucura.");
    b->dados[SAMUEL2].capitulos[13].versos[13] = _("Quanto a mim, para onde levaria o meu opróbrio? E tu passarias por um dos insensatos em Israel. Rogo-te, pois, que fales ao rei, porque ele não me negará a ti.");
    b->dados[SAMUEL2].capitulos[13].versos[14] = _("Todavia ele não quis dar ouvidos à sua voz; antes, sendo mais forte do que ela, forçou-a e se deitou com ela.");
    b->dados[SAMUEL2].capitulos[13].versos[15] = _("Depois sentiu Amnom grande aversão por ela, pois maior era a aversão que se sentiu por ela do que o amor que lhe tivera. E disse-lhe Amnom: Levanta-te, e vai-te.");
    b->dados[SAMUEL2].capitulos[13].versos[16] = _("Então ela lhe respondeu: Não há razão de me despedires; maior seria este mal do que o outro já me tens feito. Porém ele não lhe quis dar ouvidos,");
    b->dados[SAMUEL2].capitulos[13].versos[17] = _("mas, chamando o moço que o servia, disse-lhe: Deita fora a esta mulher, e fecha a porta após ela.");
    b->dados[SAMUEL2].capitulos[13].versos[18] = _("Ora, trazia ela uma túnica talar; porque assim se vestiam as filhas virgens dos reis. Então o criado dele a deitou fora, e fechou a porta após ela.");
    b->dados[SAMUEL2].capitulos[13].versos[19] = _("Pelo que Tamar, lançando cinza sobre a cabeça, e rasgando a túnica talar que trazia, pôs as mãos sobre a cabeça, e se foi andando e clamando.");
    b->dados[SAMUEL2].capitulos[13].versos[20] = _("Mas Absalão, seu irmão, lhe perguntou: Esteve Amnom, teu irmão, contigo? Ora pois, minha irmã, cala-te; é teu irmão. Não se angustie o seu coração por isto. Assim ficou Tamar, desolada, em casa de Absalão, seu irmão.");
    b->dados[SAMUEL2].capitulos[13].versos[21] = _("Quando o rei Davi ouviu todas estas coisas, muito se lhe acendeu a ira.");
    b->dados[SAMUEL2].capitulos[13].versos[22] = _("Absalão, porém, não falou com Amnom, nem mal nem bem, porque odiava a Amnom por ter ele forçado a Tamar, sua irmã.");
    b->dados[SAMUEL2].capitulos[13].versos[23] = _("Decorridos dois anos inteiros, tendo Absalão tosquiadores em Baal-Hazor, que está junto a Efraim, convidou todos os filhos do rei.");
    b->dados[SAMUEL2].capitulos[13].versos[24] = _("Foi, pois, Absalão ter com o rei, e disse: Eis que agora o teu servo faz a tosquia. Peço que o rei e os seus servos venham com o teu servo.");
    b->dados[SAMUEL2].capitulos[13].versos[25] = _("O rei, porém, respondeu a Absalão: Não, meu filho, não vamos todos, para não te sermos pesados. Absalão instou com ele; todavia ele não quis ir, mas deu-lhe a sua benção.");
    b->dados[SAMUEL2].capitulos[13].versos[26] = _("Disse-lhe Absalão: Ao menos, deixa ir conosco Amnom, meu irmão. O rei, porém, lhe perguntou: Para que iria ele contigo?");
    b->dados[SAMUEL2].capitulos[13].versos[27] = _("Mas como Absalão instasse com o rei, este deixou ir com ele Amnom, e os demais filhos do rei.");
    b->dados[SAMUEL2].capitulos[13].versos[28] = _("Ora, Absalão deu ordem aos seus servos, dizendo: Tomai sentido; quando o coração de Amnom estiver alegre do vinho, e eu vos disser: Feri a Amnom; então matai-o. Não tenhais medo; não sou eu quem vo-lo ordenou? Esforçai-vos, e sede valentes.");
    b->dados[SAMUEL2].capitulos[13].versos[29] = _("E os servos de Absalão fizeram a Amnom como Absalão lhes havia ordenado. Então todos os filhos do rei se levantaram e, montando cada um no seu mulo, fugiram.");
    b->dados[SAMUEL2].capitulos[13].versos[30] = _("Enquanto eles ainda estavam em caminho, chegou a Davi um rumor, segundo o qual se dizia: Absalão matou todos os filhos do rei; nenhum deles ficou.");
    b->dados[SAMUEL2].capitulos[13].versos[31] = _("Então o rei se levantou e, rasgando as suas vestes, lançou-se por terra; da mesma maneira todos os seus servos que lhe assistiam rasgaram as suas vestes.");
    b->dados[SAMUEL2].capitulos[13].versos[32] = _("Mas Jonadabe, filho de Siméia, irmão de Davi, disse-lhe: Não presuma o meu senhor que mataram todos os mancebos filhos do rei, porque só morreu Amnom; porque assim o tinha resolvido fazer Absalão, desde o dia em que ele forçou a Tamar, sua irmã.");
    b->dados[SAMUEL2].capitulos[13].versos[33] = _("Não se lhe meta, pois, agora no coração ao rei meu senhor o pensar que morreram todos os filhos do rei; porque só morreu Amnom.");
    b->dados[SAMUEL2].capitulos[13].versos[34] = _("Absalão, porém, fugiu. E o mancebo que estava de guarda, levantando os olhos, orou, e eis que vinha muito povo pelo caminho por detrás dele, ao lado do monte.");
    b->dados[SAMUEL2].capitulos[13].versos[35] = _("Então disse Jonadabe ao rei: Eis aí vêm os filhos do rei; conforme a palavra de teu servo, assim sucedeu.");
    b->dados[SAMUEL2].capitulos[13].versos[36] = _("Acabando ele de falar, chegaram os filhos do rei e, levantando a sua voz, choraram; e também o rei e todos os seus servos choraram amargamente.");
    b->dados[SAMUEL2].capitulos[13].versos[37] = _("Absalão, porém, fugiu, e foi ter com Talmai, filho de Amiur, rei de Gesur. E Davi pranteava a seu filho todos os dias.");
    b->dados[SAMUEL2].capitulos[13].versos[38] = _("Tendo Absalão fugido para Gesur, esteve ali três anos.");
    b->dados[SAMUEL2].capitulos[13].versos[39] = _("Então o rei Davi sentiu saudades de Absalão, pois já se tinha consolado acerca da morte de Amnom.");

    b->dados[SAMUEL2].capitulos[14].versos[1] = _("Percebendo Joabe, filho de Zeruia, que o coração do rei estava inclinado para Absalão,");
    b->dados[SAMUEL2].capitulos[14].versos[2] = _("mandou a Tecoa trazer de lá uma mulher sagaz, e disse-lhe: Ora, finge que estás de nojo; põe vestidos de luto, não te unjas com óleo, e faze-te como uma mulher que há muitos dias chora algum morto;");
    b->dados[SAMUEL2].capitulos[14].versos[3] = _("vai ter com o rei, e fala-lhe desta maneira. Então Joabe lhe pôs as palavras na boca.");
    b->dados[SAMUEL2].capitulos[14].versos[4] = _("A mulher tecoíta, pois, indo ter com o rei e prostrando-se com o rosto em terra, fez-lhe uma reverência e disse: Salva-me, o rei.");
    b->dados[SAMUEL2].capitulos[14].versos[5] = _("Ao que lhe perguntou o rei: Que tens? Respondeu ela: Na verdade eu sou viúva; morreu meu marido.");
    b->dados[SAMUEL2].capitulos[14].versos[6] = _("Tinha a tua serva dois filhos, os quais tiveram uma briga no campo e, não havendo quem os apartasse, um feriu ao outro, e o matou.");
    b->dados[SAMUEL2].capitulos[14].versos[7] = _("E eis que toda a parentela se levantou contra a tua serva, dizendo: Dá-nos aquele que matou a seu irmão, para que o matemos pela vida de seu irmão, a quem ele matou, de modo que exterminemos também o herdeiro. Assim apagarão a brasa que me ficou, de sorte a não deixarem a meu marido nem nome, nem remanescente sobre a terra.");
    b->dados[SAMUEL2].capitulos[14].versos[8] = _("Então disse o rei à mulher: Vai para tua casa, e eu darei ordem a teu respeito.");
    b->dados[SAMUEL2].capitulos[14].versos[9] = _("Respondeu a mulher tecoíta ao rei: A iniqüidade, ó rei meu senhor, venha sobre mim e sobre a casa de meu pai; e fique inculpável o rei e o seu trono.");
    b->dados[SAMUEL2].capitulos[14].versos[10] = _("Tornou o rei: Quem falar contra ti, traze-mo a mim, e nunca mais te tocará.");
    b->dados[SAMUEL2].capitulos[14].versos[11] = _("Disse ela: Ora, lembre-se o rei do Senhor seu Deus, para que o vingador do sangue não prossiga na destruição, e não extermine a meu filho. Então disse ele: Vive o Senhor, que não há de cair no chão nem um cabelo de teu filho.");
    b->dados[SAMUEL2].capitulos[14].versos[12] = _("Então disse a mulher: Permite que a tua serva fale uma palavra ao rei meu senhor. Respondeu ele: Fala.");
    b->dados[SAMUEL2].capitulos[14].versos[13] = _("Ao que disse a mulher: Por que, pois, pensas tu tal coisa contra o povo de Deus? Pois, falando o rei esta palavra, fica como culpado, visto que o rei não torna a trazer o seu desterrado.");
    b->dados[SAMUEL2].capitulos[14].versos[14] = _("Porque certamente morreremos, e serereos como águas derramadas na terra, que não se podem ajuntar mais; Deus, todavia, não tira a vida, mas cogita meios para que não fique banido dele o seu desterrado.");
    b->dados[SAMUEL2].capitulos[14].versos[15] = _("E se eu agora vim falar esta palavra ao rei meu senhor, e porque o povo me atemorizou; pelo que dizia a tua serva: Falarei, pois, ao rei; porventura fará o rei segundo a palavra da sua serva.");
    b->dados[SAMUEL2].capitulos[14].versos[16] = _("Porque o rei ouvirá, para livrar a sua serva da mão do homem que intenta exterminar da herança de Deus tanto a mim como a meu filho.");
    b->dados[SAMUEL2].capitulos[14].versos[17] = _("Dizia mais a tua serva: Que a palavra do rei meu senhor me dê um descanso; porque como o anjo de Deus é o rei, meu senhor, para discernir o bem e o mal; e o Senhor teu Deus seja contigo.");
    b->dados[SAMUEL2].capitulos[14].versos[18] = _("Então respondeu o rei à mulher: Peço-te que não me encubras o que eu te perguntar. Tornou a mulher: Fale agora o rei meu senhor.");
    b->dados[SAMUEL2].capitulos[14].versos[19] = _("Perguntou, pois, o rei: Não é verdade que a mão de Joabe está contigo em tudo isso? Respondeu a mulher: Vive a tua alma, ó rei meu senhor, que ninguém se poderá desviar, nem para a direita nem para a esquerda, de tudo quanto diz o rei meu senhor; porque Joabe, teu servo, é quem me deu ordem, e foi ele que pôs na boca da tua serva todas estas palavras;");
    b->dados[SAMUEL2].capitulos[14].versos[20] = _("para mudar a feição do negócio é que Joabe, teu servo, fez isso. Sábio, porém, é meu senhor, conforme a sabedoria do anjo de Deus, para entender tudo o que há na terra.");
    b->dados[SAMUEL2].capitulos[14].versos[21] = _("Então o rei disse a Joabe: Eis que faço o que pedes; vai, pois, e faze voltar o mancebo Absalão.");
    b->dados[SAMUEL2].capitulos[14].versos[22] = _("Então Joabe se prostrou com o rosto em terra e, fazendo uma reverência, abençoou o rei; e disse Joabe: Hoje conhece o teu servo que achei graça aos teus olhos, ó rei meu senhor, porque o rei fez segundo a palavra do teu servo.");
    b->dados[SAMUEL2].capitulos[14].versos[23] = _("Levantou-se, pois, Joabe, foi a Gesue e trouxe Absalão para Jerusalém.");
    b->dados[SAMUEL2].capitulos[14].versos[24] = _("E disse o rei: Torne ele para sua casa, mas não venha à minha presença. Tornou, pois, Absalão para sua casa, e não foi à presença do rei.");
    b->dados[SAMUEL2].capitulos[14].versos[25] = _("Não havia em todo o Israel homem tão admirável pela sua beleza como Absalão; desde a planta do pé até o alto da cabeça não havia nele defeito algum.");
    b->dados[SAMUEL2].capitulos[14].versos[26] = _("E, quando ele cortava o cabelo, o que costumava fazer no fim de cada ano, porquanto lhe pesava muito, o peso do cabelo era de duzentos siclos, segundo o peso real.");
    b->dados[SAMUEL2].capitulos[14].versos[27] = _("Nasceram a Absalão três filhos, e uma filha cujo nome era Tamar; e esta era mulher formosa à vista.");
    b->dados[SAMUEL2].capitulos[14].versos[28] = _("Assim ficou Absalão dois anos inteiros em Jerusalém, sem ver a face do rei.");
    b->dados[SAMUEL2].capitulos[14].versos[29] = _("Então Absalão mandou chamar Joabe, para o enviar ao rei; porém Joabe não quis vir a ele. Mandou chamá-lo segunda vez, mas ele não quis vir.");
    b->dados[SAMUEL2].capitulos[14].versos[30] = _("Pelo que disse aos seus servos: Vede ali o campo de Joabe pegado ao meu, onde ele tem cevada; ide, e ponde-lhe fogo. E os servos de Absalão puseram fogo ao campo:");
    b->dados[SAMUEL2].capitulos[14].versos[31] = _("Então Joabe se levantou, e veio ter com Absalão, em casa, e lhe perguntou: Por que os teus servos puseram fogo ao meu campo.");
    b->dados[SAMUEL2].capitulos[14].versos[32] = _("Respondeu Absalão a Joabe: Eis que enviei a ti, dizendo: Vem cá, para que te envie ao rei, a dizer-lhe: Para que vim de Gesur? Melhor me fora estar ainda lá. Agora, pois, veja eu a face do rei; e, se há em mim alguma culpa, que me mate.");
    b->dados[SAMUEL2].capitulos[14].versos[33] = _("Foi, pois, Joabe à presença do rei, e lho disse. Então o rei chamou Absalão, e ele entrou à presença do rei, e se prostrou com o rosto em terra diante do rei; e o rei beijou Absalão.");

    b->dados[SAMUEL2].capitulos[15].versos[1] = _("Aconteceu depois disso que Absalão adquiriu para si um carro e cavalos, e cinqüenta homens que corressem adiante dele.");
    b->dados[SAMUEL2].capitulos[15].versos[2] = _("E levantando-se Absalão cedo, parava ao lado do caminho da porta; e quando algum homem tinha uma demanda para, vir ao rei a juízo, Absalão o chamava a si e lhe dizia: De que cidade és tu? E, dizendo ele: De tal tribo de Israel é teu servo;");
    b->dados[SAMUEL2].capitulos[15].versos[3] = _("Absalão lhe dizia: Olha, a tua causa é boa e reta, porém não há da parte do rei quem te ouça.");
    b->dados[SAMUEL2].capitulos[15].versos[4] = _("Dizia mais Absalão: Ah, quem me dera ser constituído juiz na terra! para que viesse ter comigo todo homem que tivesse demanda ou questão, e eu lhe faria justiça.");
    b->dados[SAMUEL2].capitulos[15].versos[5] = _("Sucedia também que, quando alguém se chegava a ele para lhe fazer reverência, ele estendia a mão e, pegando nele o beijava.");
    b->dados[SAMUEL2].capitulos[15].versos[6] = _("Assim fazia Absalão a todo o Israel que vinha ao rei para juízo; desse modo Absalão furtava o coração dos homens de Israel.");
    b->dados[SAMUEL2].capitulos[15].versos[7] = _("Aconteceu, ao cabo de quatro anos, que Absalão disse ao rei: Deixa-me ir pagar em Hebrom o voto que fiz ao Senhor.");
    b->dados[SAMUEL2].capitulos[15].versos[8] = _("Porque, morando eu em Gesur, na Síria, fez o teu servo um voto, dizendo: Se o Senhor, na verdade, me fizer tornar a Jerusalém, servirei ao Senhor.");
    b->dados[SAMUEL2].capitulos[15].versos[9] = _("Então lhe disse o rei: Vai em paz. Levantou-se, pois, e foi para Hebrom.");
    b->dados[SAMUEL2].capitulos[15].versos[10] = _("Absalão, porém, enviou emissários por todas as tribos de Israel, dizendo: Quando ouvirdes o som da trombeta, direis: Absalão reina em Hebrom.");
    b->dados[SAMUEL2].capitulos[15].versos[11] = _("E de Jerusalém foram com Absalão duzentos homens que tinham sido convidados; mas iam na sua simplicidade, pois nada sabiam daquele desígnio.");
    b->dados[SAMUEL2].capitulos[15].versos[12] = _("Também Absalão, enquanto oferecia os seus sacrifícios, mandou vir da cidade de Siló, Aitofel, o gilonita, conselheiro de Davi. E a conspiração tornava-se poderosa, crescendo cada vez mais o número do povo que estava com Absalão.");
    b->dados[SAMUEL2].capitulos[15].versos[13] = _("Então veio um mensageiro a Davi, dizendo: O coração de todo o Israel vai após Absalão.");
    b->dados[SAMUEL2].capitulos[15].versos[14] = _("Disse, pois, Davi a todos os seus servos que estavam com ele em Jerusalém: Levantai-vos, e fujamos, porque doutra forma não poderemos escapar diante de Absalão. Apressai-vos a sair; não seja caso que ele nos apanhe de súbito, e lance sobre nós a ruína, e fira a cidade ao fio da espada.");
    b->dados[SAMUEL2].capitulos[15].versos[15] = _("Então os servos do rei lhe disseram: Eis aqui os teus servos para tudo quanto determinar o rei, nosso senhor.");
    b->dados[SAMUEL2].capitulos[15].versos[16] = _("Assim saiu o rei, com todos os de sua casa, deixando, porém, dez concubinas para guardarem a casa.");
    b->dados[SAMUEL2].capitulos[15].versos[17] = _("Tendo, pois, saído o rei com todo o povo, pararam na última casa:");
    b->dados[SAMUEL2].capitulos[15].versos[18] = _("E todos os seus servos iam ao seu lado; mas todos os quereteus, e todos os peleteus, e todos os giteus, seiscentos homens que o seguiram de Gate, caminhavam adiante do rei.");
    b->dados[SAMUEL2].capitulos[15].versos[19] = _("Disse o rei a Itai, o giteu: Por que irias tu também conosco? Volta e fica-te com o rei, porque és estrangeiro e exilado; torna a teu lugar.");
    b->dados[SAMUEL2].capitulos[15].versos[20] = _("Ontem vieste, e te levaria eu hoje conosco a vaguear? Pois eu vou para onde puder ir; volta, e lei, e contigo teus irmãos; a misericórdia e a fidelidade sejam contigo.");
    b->dados[SAMUEL2].capitulos[15].versos[21] = _("Respondeu, porém, Itai ao rei, e disse: Vive o Senhor, e vive o rei meu senhor, que no lugar em que estiver o rei meu senhor, seja para morte, seja para vida, aí estará também o eu servo.");
    b->dados[SAMUEL2].capitulos[15].versos[22] = _("Então disse Davi a Itai: Vai, pois, e passa adiante. Assim passou Itai, o giteu, e todos os seus homens, e todos os pequeninos que havia com ele.");
    b->dados[SAMUEL2].capitulos[15].versos[23] = _("Toda a terra chorava em alta voz, enquanto todo o povo passava; e o rei atravessou o ribeiro de Cedrom, e todo o povo caminhava na direção do deserto.");
    b->dados[SAMUEL2].capitulos[15].versos[24] = _("E chegou Abiatar; e veio também Zadoque, e com ele todos os levitas que levavam a arca do pacto de Deus; e puseram ali a arca de Deus, até que todo o povo acabou de sair da cidade.");
    b->dados[SAMUEL2].capitulos[15].versos[25] = _("Então disse o rei a Zadoque: Torna a levar a arca de Deus à cidade; pois, se eu achar graça aos olhos do Senhor, ele me fará voltar para lá, e me deixará ver a arca e a sua habitação.");
    b->dados[SAMUEL2].capitulos[15].versos[26] = _("Se ele, porém, disser: Não tenho prazer em ti; eis-me aqui, faça a mim o que bem lhe parecer.");
    b->dados[SAMUEL2].capitulos[15].versos[27] = _("Disse mais o rei a Zadoque, o sacerdote: Não és tu porventura vidente? volta, pois, para a cidade em paz, e contigo também teus dois filhos, Aimaaz, teu filho, e Jônatas, filho de Abiatar.");
    b->dados[SAMUEL2].capitulos[15].versos[28] = _("Vede eu me demorarei nos vaus do deserto até que tenha notícias da vossa parte.");
    b->dados[SAMUEL2].capitulos[15].versos[29] = _("Zadoque, pois, e Abiatar tornaram a levar para Jerusalém a arca de Deus, e ficaram ali.");
    b->dados[SAMUEL2].capitulos[15].versos[30] = _("Mas Davi, subindo pela encosta do monte das Oliveiras, ia chorando; tinha a cabeça coberta, e caminhava com os pés descalços. Também todo o povo que ia com ele tinha a cabeça coberta, e subia chorando sem cessar.");
    b->dados[SAMUEL2].capitulos[15].versos[31] = _("Então disseram a Davi: Aitofel está entre os que conspiraram com Absalão. Pelo que disse Davi: Ó Senhor, torna o conselho de Aitofel em loucura!");
    b->dados[SAMUEL2].capitulos[15].versos[32] = _("Ora, aconteceu que, chegando Davi ao cume, onde se costumava adorar a Deus, Husai, o arquita, veio encontrar-se com ele, com a roupa rasgada e a cabeça coberta de terra.");
    b->dados[SAMUEL2].capitulos[15].versos[33] = _("Disse-lhe Davi: Se fores comigo, ser-me-ás pesado;");
    b->dados[SAMUEL2].capitulos[15].versos[34] = _("porém se voltares para a cidade, e disseres a Absalão: Eu serei, ó rei, teu servo; como fui dantes servo de teu pai, assim agora serei teu servo; dissipar-me-ás então a conselho de Aitofel.");
    b->dados[SAMUEL2].capitulos[15].versos[35] = _("E não estão ali contigo Zadoque e Abiatar, sacerdotes? Portanto, tudo o que ouvires da casa do rei lhes dirás.");
    b->dados[SAMUEL2].capitulos[15].versos[36] = _("Eis que estão também ali com eles seus dois filhos, Aimaaz, filho de Zadoque, e Jônatas, filho de Abiatar; por eles me avisareis de tudo o que ouvirdes.");
    b->dados[SAMUEL2].capitulos[15].versos[37] = _("Husai, pois, amigo de Davi, voltou para a cidade. E Absalão entrou em Jerusalém.");

    b->dados[SAMUEL2].capitulos[16].versos[1] = _("Tendo Davi passado um pouco além do cume, eis que Ziba, o moço de Mefibosete, veio encontrar-se com ele, com um par de jumentos albardados, e sobre eles duzentos pães, cem cachos de passas, e cem de frutas de verão e um odre de vinho.");
    b->dados[SAMUEL2].capitulos[16].versos[2] = _("Perguntou, pois, o rei a Ziba: Que pretendes com isso? Respondeu Ziba: Os jumentos são para a casa do rei, para se montarem neles; e o pão e as frutas de verão para os moços comerem; e o vinho para os cansados no deserto beberem.");
    b->dados[SAMUEL2].capitulos[16].versos[3] = _("Perguntou ainda o rei: E onde está o filho de teu senhor? Respondeu Ziba ao rei: Eis que permanece em Jerusalém, pois disse: Hoje a casa de Israel me restituirá o reino de meu pai.");
    b->dados[SAMUEL2].capitulos[16].versos[4] = _("Então disse o rei a Ziba: Eis que tudo quanto pertencia a Mefibosete é teu. Ao que Ziba, inclinando-se, disse: Que eu ache graça aos teus olhos, ó rei meu senhor.");
    b->dados[SAMUEL2].capitulos[16].versos[5] = _("Tendo o rei Davi chegado a Baurim, veio saindo dali um homem da linhagem da casa de Saul, cujo nome era Simei, filho de Gêra; e, adiantando-se, proferia maldições.");
    b->dados[SAMUEL2].capitulos[16].versos[6] = _("Também atirava pedras contra Davi e todos os seus servos, ainda que todo o povo e todos os valorosos iam à direita e à esquerda do rei.");
    b->dados[SAMUEL2].capitulos[16].versos[7] = _("E, amaldiçoando-o Simei, assim dizia: Sai, sai, homem sanguinário, homem de Belial!");
    b->dados[SAMUEL2].capitulos[16].versos[8] = _("O Senhor te deu agora a paga de todo o sangue da casa de Saul, em cujo lugar tens reinado; já entregou o Senhor o reino na mão de Absalão, teu filho; e eis-te agora na desgraça, pois és um homem sanguinário.");
    b->dados[SAMUEL2].capitulos[16].versos[9] = _("Então Abisai, filho de Zeruia, disse ao rei: Por que esse cão morto amaldiçoaria ao rei meu senhor? Deixa-me passar e tirar-lhe a cabeça.");
    b->dados[SAMUEL2].capitulos[16].versos[10] = _("Disse, porém, o rei: Que tenho eu convosco, filhos de Zeruia? Por ele amaldiçoar e por lhe ter dito o Senhor: Amaldiçoa a Davi; quem dirá: Por que assim fizeste?");
    b->dados[SAMUEL2].capitulos[16].versos[11] = _("Disse mais Davi a Abisai, e a todos os seus servos: Eis que meu filho, que saiu das minhas entranhas, procura tirar-me a vida; quanto mais ainda esse benjamita? Deixai-o; deixai que amaldiçoe, porque o Senhor lho ordenou.");
    b->dados[SAMUEL2].capitulos[16].versos[12] = _("Porventura o Senhor olhará para a minha aflição, e me pagará com bem a maldição deste dia.");
    b->dados[SAMUEL2].capitulos[16].versos[13] = _("Prosseguiam, pois, o seu caminho, Davi e os seus homens, enquanto Simei ia pela encosta do monte, defronte dele, caminhando e amaldiçoando, e atirava pedras contra ele, e levantava poeira.");
    b->dados[SAMUEL2].capitulos[16].versos[14] = _("E o rei e todo o povo que ia com ele chegaram cansados ao Jordão; e ali descansaram.");
    b->dados[SAMUEL2].capitulos[16].versos[15] = _("Absalão e todo o povo, os homens de Israel, vieram a Jerusalém; e Aitofel estava com ele.");
    b->dados[SAMUEL2].capitulos[16].versos[16] = _("E chegando Husai, o arquita, amigo de Davi, a Absalão, disse-lhe: Viva o rei, viva o rei!");
    b->dados[SAMUEL2].capitulos[16].versos[17] = _("Absalão, porém, perguntou a Husai: E esta a tua benevolência para com o teu amigo? Por que não foste com o teu amigo?");
    b->dados[SAMUEL2].capitulos[16].versos[18] = _("Respondeu-lhe Husai: Não; pois aquele a quem o Senhor, e este povo, e todos os homens de Israel têm escolhido, dele serei e com ele ficarei.");
    b->dados[SAMUEL2].capitulos[16].versos[19] = _("E, demais disto, a quem serviria eu? Porventura não seria a seu filho? como servi a teu pai, assim servirei a ti.");
    b->dados[SAMUEL2].capitulos[16].versos[20] = _("Então disse Absalão a Aitofel: Dai o vosso conselho sobre o que devemos fazer.");
    b->dados[SAMUEL2].capitulos[16].versos[21] = _("Respondeu Aitofel a Absalão: Entra às concubinas de teu pai, que ele deixou para guardarem a casa; e assim todo o Israel ouvirá que te fizeste aborrecível para com teu pai, e se fortalecerão as mãos de todos os que estão contigo.");
    b->dados[SAMUEL2].capitulos[16].versos[22] = _("Estenderam, pois, para Absalão uma tenda no terraço; e entrou Absalão às concubinas de seu pai, à vista de todo o Israel.");
    b->dados[SAMUEL2].capitulos[16].versos[23] = _("E o conselho que Aitofel dava naqueles dias era como se o oráculo de Deus se consultara; tal era todo o conselho de Aitofel, tanto para com Davi como para Absalão.");

    b->dados[SAMUEL2].capitulos[17].versos[1] = _("Disse mais Aitofel a Absalão: Deixa-me escolher doze mil homens, e me levantarei, e perseguirei a Davi esta noite.");
    b->dados[SAMUEL2].capitulos[17].versos[2] = _("Irei sobre ele, enquanto está cansado, e fraco de mãos, e o espantarei: então fugirá todo o povo que está com ele. Ferirei tão-somente o rei;");
    b->dados[SAMUEL2].capitulos[17].versos[3] = _("e farei tornar a ti todo o povo, como uma noiva à casa do seu esposo; pois é a vida dum só homem que tu buscas; assim todo o povo estará em paz.");
    b->dados[SAMUEL2].capitulos[17].versos[4] = _("E este conselho agradou a Absalão, e a todos os anciãos de Israel.");
    b->dados[SAMUEL2].capitulos[17].versos[5] = _("Disse, porém, Absalão: Chamai agora a Husai, o arquita, e ouçamos também o que ele diz.");
    b->dados[SAMUEL2].capitulos[17].versos[6] = _("Quando Husai chegou a Absalão, este lhe disse: Desta maneira falou Aitofel; faremos conforme a sua palavra? Se não, fala tu.");
    b->dados[SAMUEL2].capitulos[17].versos[7] = _("Então disse Husai a Absalão: O conselho que Aitofel deu esta vez não é bom.");
    b->dados[SAMUEL2].capitulos[17].versos[8] = _("Acrescentou Husai: Tu bem sabes que teu pai e os seus homens são valentes, e que estão com o espírito amargurado, como a ursa no campo, roubada dos seus cachorros; além disso teu pai é homem de guerra, e não passará a noite com o povo.");
    b->dados[SAMUEL2].capitulos[17].versos[9] = _("Eis que agora está ele escondido nalguma cova, ou em qualquer outro lugar; e será que, caindo alguns no primeiro ataque, todo o que o ouvir dirá: Houve morticínio entre o povo que segue a Absalão.");
    b->dados[SAMUEL2].capitulos[17].versos[10] = _("Então até o homem valente, cujo coração é como coração de leão, sem dúvida desmaiará; porque todo o Israel sabe que teu pai é valoroso, e que são valentes os que estão com ele.");
    b->dados[SAMUEL2].capitulos[17].versos[11] = _("Eu, porém, aconselho que com toda a pressa se ajunte a ti todo o Israel, desde Dã até Berseba, em multidão como a areia do mar; e que tu em pessoa vás à peleja.");
    b->dados[SAMUEL2].capitulos[17].versos[12] = _("Então iremos a ele, em qualquer lugar em que se achar, e desceremos sobre ele, como o orvalho cai sobre a terra; e não ficará dele e de todos os homens que estão com ele nem sequer um só.");
    b->dados[SAMUEL2].capitulos[17].versos[13] = _("se ele, porém, se retirar para alguma cidade, todo o Israel trará cordas àquela cidade, e arrastá-la-emos até o ribeiro, até que não se ache ali nem uma só pedrinha");
    b->dados[SAMUEL2].capitulos[17].versos[14] = _("Então Absalão e todos os homens e Israel disseram: Melhor é o conselho de Husai, o arquita, do que o conselho de Aitofel: Porque assim o Senhor o ordenara, para aniquilar o bom conselho de Aitofel, a fim de trazer o mal sobre Absalão.");
    b->dados[SAMUEL2].capitulos[17].versos[15] = _("Também disse Husai a Zadoque e a Abiatar, sacerdotes: Assim e assim aconselhou Aitofel a Absalão e aos anciãos de Israel; porém eu aconselhei assim e assim.");
    b->dados[SAMUEL2].capitulos[17].versos[16] = _("Agora, pois, mandai apressadamente avisar a Davi, dizendo: Não passes esta noite nos vaus do deserto; mas passa sem falta à outra banda, para que não seja devorado o rei, e todo o povo que com ele está.");
    b->dados[SAMUEL2].capitulos[17].versos[17] = _("Ora, Jônatas e Aimaaz estavam esperando junto a En-Rogel; e foi uma criada, e lhes avisou, para que eles fossem e o dissessem ao rei Davi; pois não deviam ser vistos entrando na cidade.");
    b->dados[SAMUEL2].capitulos[17].versos[18] = _("Viu-os todavia um moço, e avisou a Absalão. Ambos, porém, partiram apressadamente, e entraram em casa de um homem, em Baurim, o qual tinha no pátio de sua casa um poço, para o qual eles desceram.");
    b->dados[SAMUEL2].capitulos[17].versos[19] = _("E a mulher, tomando a tampa, colocou-a sobre a boca do poço, e espalhou grão triturado sobre ela; assim nada se soube.");
    b->dados[SAMUEL2].capitulos[17].versos[20] = _("Chegando, pois, os servos de Absalão àquela casa, perguntaram à mulher: Onde estão Aimaaz e Jônatas? Respondeu-lhes a mulher: Já passaram a corrente das águas. E, havendo-os procurado sem os encontrarem, voltaram para Jerusalém.");
    b->dados[SAMUEL2].capitulos[17].versos[21] = _("Depois que eles partiram, Aimaaz e Jônatas, saindo do poço, foram e avisaram a Davi; e disseram-lhe: Levantai-vos, e passai depressa as águas, porque assim e assim aconselhou contra vós Aitofel.");
    b->dados[SAMUEL2].capitulos[17].versos[22] = _("Então se levantou Davi e todo o povo que com ele estava, e passaram o Jordão; e ao raiar da manhã não faltava nem um só que não o tivesse passado.");
    b->dados[SAMUEL2].capitulos[17].versos[23] = _("Vendo, pois, Aitofel que não se havia seguido o seu conselho, albardou o jumento e, partindo, foi para casa, para a sua cidade; e, tendo posto em ordem a sua casa, se enforcou e morreu; e foi sepultado na sepultura de seu pai.");
    b->dados[SAMUEL2].capitulos[17].versos[24] = _("Então Davi veio a Maanaim; e Absalão passou o Jordão, ele e todos os homens de Israel com ele.");
    b->dados[SAMUEL2].capitulos[17].versos[25] = _("E Absalão colocou Amasa em lugar de Joabe sobre o exército. Ora, Amasa era filho de um homem que se chamava Itra, o jizreelita, o qual entrara a Abigail, filha de Naás e irmã de Zeruia, mãe de Joabe.");
    b->dados[SAMUEL2].capitulos[17].versos[26] = _("Israel e Absalão se acamparam na terra de Gileade.");
    b->dados[SAMUEL2].capitulos[17].versos[27] = _("Tendo Davi chegado a Maanaim, Sobi, filho de Naás, de Rabá dos filhos de Amom, e Maquir, filho de Amiel, de Lo-Debar, e Barzilai, o gileadita, de Rogelim,");
    b->dados[SAMUEL2].capitulos[17].versos[28] = _("tomaram camas, bacias e vasilhas de barro; trigo, cevada, farinha, grão tostado, favas, lentilhas e torradas;");
    b->dados[SAMUEL2].capitulos[17].versos[29] = _("mel, manteiga, ovelhas e queijos de vaca, e os trouxeram a Davi e ao povo que com ele estava, para comerem; pois diziam: O povo está faminto, cansado e sedento, no deserto.");

    b->dados[SAMUEL2].capitulos[18].versos[1] = _("Então Davi contou o povo que tinha consigo, e pôs sobre ele chefes de mil e chefes de cem.");
    b->dados[SAMUEL2].capitulos[18].versos[2] = _("E Davi enviou o exército, um terço sob o mando de Joabe, outro terço sob o mando de Abisai, filho de Zeruia, irmão de Joabe, e outro terço sob o mando de Itai, o giteu. E disse o rei ao povo: Eu também sairei convosco.");
    b->dados[SAMUEL2].capitulos[18].versos[3] = _("Mas o povo respondeu: Não sairás; porque se fugirmos, eles não se importarão conosco; nem se importarão conosco ainda que morra metade de nós; porque tu vales por dez mil tais como nós. Melhor será que da cidade nos mandes socorro.");
    b->dados[SAMUEL2].capitulos[18].versos[4] = _("Respondeu-lhes o rei: Farei o que vos parecer bem. E o rei se pôs ao lado da porta, e todo o povo saiu em centenas e em milhares.");
    b->dados[SAMUEL2].capitulos[18].versos[5] = _("E o rei deu ordem a Joabe, a Abisai e a Itai, dizendo: Tratai brandamente, por amor de mim, o mancebo Absalão. E todo o povo ouviu quando o rei deu ordem a todos os chefes acerca de Absalão.");
    b->dados[SAMUEL2].capitulos[18].versos[6] = _("Assim saiu o povo a campo contra Israel; e deu-se a batalha no bosque de Efraim.");
    b->dados[SAMUEL2].capitulos[18].versos[7] = _("Ali o povo de Israel foi derrotado pelos servos de Davi; e naquele dia houve ali grande morticínio, de vinte mil homens.");
    b->dados[SAMUEL2].capitulos[18].versos[8] = _("Pois a batalha se estendeu sobre a face de toda aquela terra, e o bosque consumiu mais gente naquele dia do que a espada.");
    b->dados[SAMUEL2].capitulos[18].versos[9] = _("Por acaso Absalão se encontrou com os servos de Davi; e Absalão ia montado num mulo e, entrando o mulo debaixo dos espessos ramos de um grande carvalho, pegou-se a cabeça de Absalão no carvalho, e ele ficou pendurado entre o céu e a terra; e o mulo que estava debaixo dele passou adiante.");
    b->dados[SAMUEL2].capitulos[18].versos[10] = _("um homem, vendo isso, contou-o a Joabe, dizendo: Eis que vi Absalão pendurado dum carvalho.");
    b->dados[SAMUEL2].capitulos[18].versos[11] = _("Então disse Joabe ao homem que lho contara: Pois que o viste, por que não o derrubaste logo por terra? E eu te haveria dado dez siclos de prata e um cinto.");
    b->dados[SAMUEL2].capitulos[18].versos[12] = _("Respondeu, porém, o homem a Joabe: Ainda que eu pudesse pesar nas minhas mãos mil siclos de prata, não estenderia a mão contra o filho do rei; pois bem ouvimos que o rei deu ordem a ti, e a Abisai, e a Itai, dizendo: Guardai-vos, cada um, de tocar no mancebo Absalão.");
    b->dados[SAMUEL2].capitulos[18].versos[13] = _("E se eu tivesse procedido falsamente contra a sua vida, coisa nenhuma se esconderia ao rei, e tu mesmo te oporias a mim:");
    b->dados[SAMUEL2].capitulos[18].versos[14] = _("Então disse Joabe: Não posso demorar-me assim contigo aqui. E tomou na mão três dardos, e traspassou com eles o coração de Absalão, estando ele ainda vivo no meio do carvalho.");
    b->dados[SAMUEL2].capitulos[18].versos[15] = _("E o cercaram dez mancebos, que levavam as armas de Joabe; e feriram a Absalão, e o mataram.");
    b->dados[SAMUEL2].capitulos[18].versos[16] = _("Então tocou Joabe a buzina, e o povo voltou de perseguir a Israel; porque Joabe deteve o povo.");
    b->dados[SAMUEL2].capitulos[18].versos[17] = _("E tomaram a Absalão e, lançando-o numa grande cova no bosque, levantaram sobre ele mui grande montão de pedras. E todo o Israel fugiu, cada um para a sua tenda.");
    b->dados[SAMUEL2].capitulos[18].versos[18] = _("Ora, Absalão, quando ainda vivia, tinha feito levantar para si a coluna que está no vale do rei; pois dizia: Nenhum filho tenho para conservar a memória o meu nome. E deu o seu próprio nome àquela coluna, a qual até o dia de hoje se chama o Pilar de Absalão.");
    b->dados[SAMUEL2].capitulos[18].versos[19] = _("Então disse Aimaaz, filho de Zadoque: Deixa-me correr, e anunciarei ao rei que o Senhor o vingou a mão e seus inimigos.");
    b->dados[SAMUEL2].capitulos[18].versos[20] = _("Mas Joabe lhe disse: Tu não serás hoje o portador das novas; outro dia as levarás, mas hoje não darás a nova, porque é morto o filho do rei.");
    b->dados[SAMUEL2].capitulos[18].versos[21] = _("Disse, porém, Joabe ao cuchita: Vai tu, e dize ao rei o que viste. O cuchita se inclinou diante de Joabe, e saiu correndo.");
    b->dados[SAMUEL2].capitulos[18].versos[22] = _("Então prosseguiu Aimaaz, filho de Zadoque, e disse a Joabe: Seja o que for, deixa-me também correr após o cuchita. Respondeu Joabe: Para que agora correrias tu, meu filho, pois não receberias recompensa pelas novas?");
    b->dados[SAMUEL2].capitulos[18].versos[23] = _("seja o que for, disse Aimaaz, correrei. Disse-lhe, pois, Joabe: Corre. Então Aimaaz correu pelo caminho da planície, e passou adiante do cuchita.");
    b->dados[SAMUEL2].capitulos[18].versos[24] = _("Ora, Davi estava sentado entre as duas portas; e a sentinela subiu ao terraço da porta junto ao muro e, levantando os olhos, viu um homem que corria só.");
    b->dados[SAMUEL2].capitulos[18].versos[25] = _("Gritou, pois, a sentinela, e o disse ao rei. Respondeu o rei: Se vem só, é portador de novas. Vinha, pois, o mensageiro aproximando-se cada vez mais.");
    b->dados[SAMUEL2].capitulos[18].versos[26] = _("Então a sentinela viu outro homem que corria, e gritou ao porteiro, e disse: Eis que lá vem outro homem correndo só. Então disse o rei: Também esse traz novas.");
    b->dados[SAMUEL2].capitulos[18].versos[27] = _("Disse mais a sentinela: O correr do primeiro parece ser o correr de Aimaaz, filho de Zadoque. Então disse o rei: Este é homem de bem, e virá com boas novas.");
    b->dados[SAMUEL2].capitulos[18].versos[28] = _("Gritou, pois, Aimaaz, e disse ao rei: Paz! E inclinou-se ao rei com o rosto em terra, e disse: Bendito seja o Senhor teu Deus, que entregou os homens que levantaram a mão contra o rei meu senhor.");
    b->dados[SAMUEL2].capitulos[18].versos[29] = _("Então perguntou o rei: Vai bem o mancebo Absalão? Respondeu Aimaaz: Quando Joabe me mandou a mim, o servo do rei, vi um grande alvoroço; porem não sei o que era.");
    b->dados[SAMUEL2].capitulos[18].versos[30] = _("Disse-lhe o rei: Põe-te aqui ao lado. E ele se pôs ao lado, e esperou de pé.");
    b->dados[SAMUEL2].capitulos[18].versos[31] = _("Nisso chegou o cuchita, e disse: Novas para o rei meu senhor. Pois que hoje o Senhor te vingou da mão de todos os que se levantaram contra ti.");
    b->dados[SAMUEL2].capitulos[18].versos[32] = _("Então perguntou o rei ao cuchita: Vai bem o mancebo Absalão? Respondeu o cuchita: Sejam como aquele mancebo os inimigos do rei meu senhor, e todos os que se levantam contra ti para te fazerem mal.");
    b->dados[SAMUEL2].capitulos[18].versos[33] = _("Pelo que o rei ficou muito comovido e, subindo à sala que estava por cima da porta, pôs-se a chorar; e andando, dizia assim: Meu filho Absalão, meu filho, meu filho Absalão! quem me dera que eu morrera por ti, Absalão, meu filho, meu filho!");

    b->dados[SAMUEL2].capitulos[19].versos[1] = _("Disseram a Joabe: Eis que o rei está chorando e se lamentando por Absalão.");
    b->dados[SAMUEL2].capitulos[19].versos[2] = _("Então a vitória se tornou naquele dia em tristeza para todo o povo, porque nesse dia o povo ouviu dizer: O rei está muito triste por causa de seu filho.");
    b->dados[SAMUEL2].capitulos[19].versos[3] = _("E nesse dia o povo entrou furtivamente na cidade, como o faz quando, envergonhado, foge da peleja.");
    b->dados[SAMUEL2].capitulos[19].versos[4] = _("Estava, pois, o rei com o rosto coberto, e clamava em alta voz: Meu filho Absalão, Absalão meu filho, meu filho!");
    b->dados[SAMUEL2].capitulos[19].versos[5] = _("Então entrou Joabe na casa onde estava o rei, e disse: Hoje envergonhaste todos os teus servos, que livraram neste dia a tua vida, a vida de teus filhos e filhas, e a vida de tuas mulheres e concubinas,");
    b->dados[SAMUEL2].capitulos[19].versos[6] = _("amando aos que te odeiam, e odiando aos que te amam. Porque hoje dás a entender que nada valem para ti nem chefes nem servos; pois agora entendo que se Absalão vivesse, e todos nós hoje fôssemos mortos, ficarias bem contente.");
    b->dados[SAMUEL2].capitulos[19].versos[7] = _("Levanta-te, pois, agora; sai e fala ao coração de teus servos. Porque pelo Senhor te juro que, se não saíres, nem um só homem ficará contigo esta noite; e isso te será pior do que todo o mal que tem vindo sobre ti desde a tua mocidade até agora.");
    b->dados[SAMUEL2].capitulos[19].versos[8] = _("Pelo que o rei se levantou, e se sentou à porta; e avisaram a todo o povo, dizendo: Eis que o rei está sentado à porta. Então todo o povo veio apresentar-se diante do rei. Ora, Israel havia fugido, cada um para a sua tenda.");
    b->dados[SAMUEL2].capitulos[19].versos[9] = _("Entrementes todo o povo, em todas as tribos de Israel, andava altercando entre si, dizendo: O rei nos tirou das mãos de nossos inimigos, e nos livrou das mãos dos filisteus; e agora fugiu da terra por causa de Absalão.");
    b->dados[SAMUEL2].capitulos[19].versos[10] = _("Também Absalão, a quem ungimos sobre nós, morreu na peleja. Agora, pois, porque vos calais, e não fazeis voltar o rei?");
    b->dados[SAMUEL2].capitulos[19].versos[11] = _("Então o rei Davi mandou dizer a Zadoque e a Abiatar, sacerdotes: Falai aos anciãos de Judá, dizendo: Por que seríeis vós os últimos em tornar a trazer o rei para sua casa? Porque a palavra de todo o Israel tem chegado ao rei, até a sua casa.");
    b->dados[SAMUEL2].capitulos[19].versos[12] = _("Vós sois meus irmãos; meus ossos e minha carne sois vós; por que, pois, seríeis os últimos em tornar a trazer o rei?");
    b->dados[SAMUEL2].capitulos[19].versos[13] = _("Dizei a Amasa: Porventura não és tu meu osso e minha carne? Assim me faça Deus e outro tanto, se não fores chefe do exercito diante e mim para sempre, em lugar de Joabe.");
    b->dados[SAMUEL2].capitulos[19].versos[14] = _("Assim moveu ele o coração de todos os homens de Judá, como se fosse o de um só homem; e enviaram ao rei, dizendo: Volta, com todos os teus servos.");
    b->dados[SAMUEL2].capitulos[19].versos[15] = _("Então o rei voltou, e chegou até o Jordão; e Judá veio a Gilgal, para encontrar-se com o rei, a fim de fazê-lo passar o Jordão.");
    b->dados[SAMUEL2].capitulos[19].versos[16] = _("Ora, apressou-se Simei, filho de Gêra, benjamita, que era de Baurim, e desceu com os homens de Judá a encontrar-se com o rei Davi;");
    b->dados[SAMUEL2].capitulos[19].versos[17] = _("e com ele mil homens de Benjamim, como também Ziba, servo da casa de Saul, e seus quinze filhos, e seus vinte servos com ele; desceram apressadamente ao Jordão adiante do rei,");
    b->dados[SAMUEL2].capitulos[19].versos[18] = _("atravessando o vau para trazer a casa do rei e para fazer o que aprouvesse a ele. Quando o rei ia passar o Jordão, Simei, filho de Gêra, se prostrou diante dele,");
    b->dados[SAMUEL2].capitulos[19].versos[19] = _("e lhe disse: Não me impute meu senhor à minha culpa, e não te lembres do que tão perversamente fez teu servo, no dia em que o rei meu senhor saiu de Jerusalém; não conserve o rei isso no coração.");
    b->dados[SAMUEL2].capitulos[19].versos[20] = _("Porque eu, teu servo, deveras confesso que pequei; por isso eis que eu sou o primeiro, de toda a casa de José, a descer ao encontro do rei meu senhor.");
    b->dados[SAMUEL2].capitulos[19].versos[21] = _("Respondeu Abisai, filho de Zeruia, dizendo: Não há de ser morto Simei por haver amaldiçoado ao ungido do Senhor?");
    b->dados[SAMUEL2].capitulos[19].versos[22] = _("Mas Davi disse: Que tenho eu convosco, filhos de Zeruia, para que hoje me sejais adversários? Será morto alguém hoje em Israel? pois não sei eu que hoje sou rei sobre Israel?");
    b->dados[SAMUEL2].capitulos[19].versos[23] = _("Então disse o rei a Simei: Não morrerás. E o rei lho jurou.");
    b->dados[SAMUEL2].capitulos[19].versos[24] = _("Também Mefibosete, filho de Saul, desceu a encontrar-se com o rei, e não cuidara dos pés, nem fizera a barba, nem lavara as suas vestes desde o dia em que o rei saíra até o dia em que voltou em paz.");
    b->dados[SAMUEL2].capitulos[19].versos[25] = _("E sucedeu que, vindo ele a Jerusalém a encontrar-se com o rei, este lhe perguntou: Por que não foste comigo, Mefibosete?");
    b->dados[SAMUEL2].capitulos[19].versos[26] = _("Respondeu ele: O rei meu senhor, o meu servo me enganou. Porque o teu servo dizia: Albardarei um jumento, para nele montar e ir com o rei; pois o teu servo é coxo.");
    b->dados[SAMUEL2].capitulos[19].versos[27] = _("E ele acusou falsamente o teu servo diante do rei meu senhor; porém o rei meu senhor é como um anjo de Deus; faze, pois, o que bem te parecer.");
    b->dados[SAMUEL2].capitulos[19].versos[28] = _("Pois toda a casa de meu pai não era senão de homens dignos de morte diante do rei meu senhor; contudo, puseste teu servo entre os que comem à tua mesa. E que direito mais tenho eu de clamar ainda ao rei.");
    b->dados[SAMUEL2].capitulos[19].versos[29] = _("Ao que lhe respondeu o rei: Por que falas ainda de teus negócios? Já decidi: Tu e Ziba reparti as terras.");
    b->dados[SAMUEL2].capitulos[19].versos[30] = _("Então disse Mefibosete ao rei: Deixe que ele tome tudo, uma vez que o rei meu senhor já voltou em paz à sua casa.");
    b->dados[SAMUEL2].capitulos[19].versos[31] = _("Também Barzilai, o gileadita, desceu de Rogelim, e passou com o rei o Jordão, para acompanhá-lo até a outra banda do rio.");
    b->dados[SAMUEL2].capitulos[19].versos[32] = _("E era Barzilai mui velho, da idade de oitenta anos; e ele tinha provido o rei de víveres enquanto este se demorara em Maanaim, pois era homem muito rico.");
    b->dados[SAMUEL2].capitulos[19].versos[33] = _("Disse, pois, o rei a Barzilai: Passa tu comigo e eu te sustentarei em Jerusalém, em minha companhia.");
    b->dados[SAMUEL2].capitulos[19].versos[34] = _("Barzilai, porém, respondeu ao rei: Quantos anos viverei ainda, para que suba com o rei a Jerusalém.");
    b->dados[SAMUEL2].capitulos[19].versos[35] = _("Oitenta anos tenho hoje; poderei eu discernir entre e bom e o mau? poderá o teu servo perceber sabor no que comer e beber? poderei eu mais ouvir a voz dos cantores e das cantoras? e por que será o teu servo ainda pesado ao rei meu senhor?");
    b->dados[SAMUEL2].capitulos[19].versos[36] = _("O teu servo passará com o rei até um pouco além do Jordão. Por que me daria o rei tal recompensa?");
    b->dados[SAMUEL2].capitulos[19].versos[37] = _("Deixa voltar o teu servo, para que eu morra na minha cidade, junto à sepultura de meu pai e de minha mãe. Mas eis aí o teu servo Quimã; passe ele com o rei meu senhor, e faze-lhe o que for do teu agrado.");
    b->dados[SAMUEL2].capitulos[19].versos[38] = _("Ao que disse o rei: Quimã passará comigo, e eu lhe farei o que te parecer bem, e tudo quanto me pedires te farei.");
    b->dados[SAMUEL2].capitulos[19].versos[39] = _("Havendo, pois, todo o povo passado o Jordão, e tendo passado também o rei, beijou o rei a Barzilai, e o abençoou; e este voltou para o seu lugar.");
    b->dados[SAMUEL2].capitulos[19].versos[40] = _("Dali passou o rei a Gilgal, e Quimã com ele; e todo o povo de Judá, juntamente com a metade do povo de Israel, conduziu o rei.");
    b->dados[SAMUEL2].capitulos[19].versos[41] = _("Então todos os homens de Israel vieram ter com o rei, e lhe disseram: Por que te furtaram nossos irmãos, os homens de Judá, e fizeram passar o Jordão o rei e a sua casa, e todos os seus homens com ele?");
    b->dados[SAMUEL2].capitulos[19].versos[42] = _("Responderam todos os homens de Judá aos homens de Israel: Porquanto o rei é nosso parente: Por que vos irais por isso. Acaso temos comido à custa do rei, ou nos deu ele algum presente?");
    b->dados[SAMUEL2].capitulos[19].versos[43] = _("Ao que os homens de Israel responderam aos homens de Judá: Dez partes temos no rei; mais temos nós em Davi do que vós. Por que, pois, fizestes pouca conta de nós. Não foi a nossa palavra a primeira, para tornar a trazer o nosso rei? Porém a palavra dos homens de Judá foi mais forte do que a palavra dos homens de Israel.");

    b->dados[SAMUEL2].capitulos[20].versos[1] = _("Ora, sucedeu achar-se ali um homem de Belial, cujo nome era Sebá, filho de Bicri, homem de Benjamim, o qual tocou a buzina, e disse: Não temos parte em Davi, nem herança no filho de Jessé; cada um à sua tenda, ó Israel!");
    b->dados[SAMUEL2].capitulos[20].versos[2] = _("Então todos os homens de Israel se separaram de Davi, e seguiram a Sebá, filho de Bicri; porém os homens de Judá seguiram ao seu rei desde o Jordão até Jerusalém.");
    b->dados[SAMUEL2].capitulos[20].versos[3] = _("Quando Davi chegou à sua casa em Jerusalém, tomou as dez concubinas que deixara para guardarem a casa, e as pôs numa casa, sob guarda, e as sustentava; porém não entrou a elas. Assim estiveram encerradas até o dia da sua morte, vivendo como viúvas.");
    b->dados[SAMUEL2].capitulos[20].versos[4] = _("Disse então o rei a Amasa: Convoca-me dentro de três dias os homens de Judá, e apresenta-te aqui.");
    b->dados[SAMUEL2].capitulos[20].versos[5] = _("Foi, pois, Amasa para convocar a Judá, porém demorou-se além do tempo que o rei lhe designara.");
    b->dados[SAMUEL2].capitulos[20].versos[6] = _("Então disse Davi a Abisai: Mais mal agora nos fará Sebá, filho de Bicri, do que Absalão; toma, pois, tu os servos de teu senhor, e persegue-o, para que ele porventura não ache para si cidades fortificadas, e nos escape à nossa vista.");
    b->dados[SAMUEL2].capitulos[20].versos[7] = _("Então saíram atrás dele os homens de Joabe, e os quereteus, e os peleteus, e todos os valentes; saíram de Jerusalém para perseguirem a Sebá, filho de Bicri.");
    b->dados[SAMUEL2].capitulos[20].versos[8] = _("Quando chegaram à pedra grande que está junto a Gibeão, Amasa lhes veio ao encontro. Estava Joabe cingido do seu traje de guerra que vestira, e sobre ele um cinto com a espada presa aos seus lombos, na sua bainha; e, adiantando-se ele, a espada caiu da bainha.");
    b->dados[SAMUEL2].capitulos[20].versos[9] = _("E disse Joabe a Amasa: Vais bem, meu irmão? E Joabe, com a mão direita, pegou da barba de Amasa, para o beijar.");
    b->dados[SAMUEL2].capitulos[20].versos[10] = _("Amasa, porém, não reparou na espada que está na mão de Joabe; de sorte que este o feriu com ela no ventre, derramando-lhe por terra as entranhas, sem feri-lo segunda vez; e ele morreu. Então Joabe e Abisai, seu irmão, perseguiram a Sebá, filho de Bicri.");
    b->dados[SAMUEL2].capitulos[20].versos[11] = _("Mas um homem dentre os servos de Joabe ficou junto a Amasa, e dizia: Quem favorece a Joabe, e quem é por Davi, siga a Joabe.");
    b->dados[SAMUEL2].capitulos[20].versos[12] = _("E Amasa se revolvia no seu sangue no meio do caminho. E aquele homem, vendo que todo o povo parava, removeu Amasa do caminho para o campo, e lançou sobre ele um manto, porque viu que todo aquele que chegava ao pé dele parava.");
    b->dados[SAMUEL2].capitulos[20].versos[13] = _("Mas removido Amasa do caminho, todos os homens seguiram a Joabe, para perseguirem a Sebá, filho de Bicri.");
    b->dados[SAMUEL2].capitulos[20].versos[14] = _("Então Sebá passou por todas as tribos de Israel até Abel e Bete-Maacá; e todos os beritas, ajuntando-se, também o seguiram.");
    b->dados[SAMUEL2].capitulos[20].versos[15] = _("Vieram, pois, e cercaram a Sebá em Abel de Bete-Maacá; e levantaram contra a cidade um montão, que se elevou defronte do muro; e todo o povo que estava com Joabe batia o muro para derrubá-lo.");
    b->dados[SAMUEL2].capitulos[20].versos[16] = _("Então uma mulher sábia gritou de dentro da cidade: Ouvi! ouvi! Dizei a Joabe: Chega-te cá, para que eu te fale.");
    b->dados[SAMUEL2].capitulos[20].versos[17] = _("Ele, pois, se chegou perto dela; e a mulher perguntou: Tu és Joabe? Respondeu ele: Sou. Ela lhe disse: Ouve as palavras de tua serva. Disse ele: Estou ouvindo.");
    b->dados[SAMUEL2].capitulos[20].versos[18] = _("Então falou ela, dizendo: Antigamente costumava-se dizer: Que se peça conselho em Abel; e era assim que se punha termo às questões.");
    b->dados[SAMUEL2].capitulos[20].versos[19] = _("Eu sou uma das pacíficas e das fiéis em Israel; e tu procuras destruir uma cidade que é mãe em Israel; por que, pois, devorarias a herança do Senhor?");
    b->dados[SAMUEL2].capitulos[20].versos[20] = _("Então respondeu Joabe, e disse: Longe, longe de mim que eu tal faça, que eu devore ou arruíne!");
    b->dados[SAMUEL2].capitulos[20].versos[21] = _("A coisa não é assim; porém um só homem da região montanhosa de Efraim, cujo nome é Sebá, filho de Bicri, levantou a mão contra o rei, contra Davi; entregai-me só este, e retirar-me-ei da cidade. E disse a mulher a Joabe: Eis que te será lançada a sua cabeça pelo muro.");
    b->dados[SAMUEL2].capitulos[20].versos[22] = _("A mulher, na sua sabedoria, foi ter com todo o povo; e cortaram a cabeça de Sebá, filho de Bicri, e a lançaram a Joabe. Este, pois, tocou a buzina, e eles se retiraram da cidade, cada um para sua tenda. E Joabe voltou a Jerusalém, ao rei.");
    b->dados[SAMUEL2].capitulos[20].versos[23] = _("Ora, Joabe estava sobre todo o exército de Israel; e Benaías, filho de Jeoiada, sobre os quereteus e os peleteus;");
    b->dados[SAMUEL2].capitulos[20].versos[24] = _("e Adorão sobre a gente de trabalhos forçados; Jeosafá, filho de Ailude, era cronista;");
    b->dados[SAMUEL2].capitulos[20].versos[25] = _("Seva era escrivão; Zadoque e Abiatar, sacerdotes;");
    b->dados[SAMUEL2].capitulos[20].versos[26] = _("e Ira, o jairita, era o oficial-mor de Davi.");

    b->dados[SAMUEL2].capitulos[21].versos[1] = _("Nos dias de Davi houve uma fome de três anos consecutivos; pelo que Davi consultou ao Senhor; e o Senhor lhe disse: E por causa de Saul e da sua casa sanguinária, porque matou os gibeonitas.");
    b->dados[SAMUEL2].capitulos[21].versos[2] = _("Então o rei chamou os gibeonitas e falou com eles {ora, os gibeonitas não eram dos filhos de Israel, mas do restante dos amorreus; e os filhos de Israel tinham feito pacto com eles; porém Saul, no seu zelo pelos filhos de Israel e de Judá, procurou feri-los};");
    b->dados[SAMUEL2].capitulos[21].versos[3] = _("perguntou, pois, Davi aos gibeonitas: Que quereis que eu vos faça. e como hei de fazer expiação, para que abençoeis a herança do Senhor?");
    b->dados[SAMUEL2].capitulos[21].versos[4] = _("Então os gibeonitas lhe disseram: Não é por prata nem ouro que temos questão com Saul e com a sua casa; nem tampouco cabe a nós matar pessoa alguma em Israel. Disse-lhes Davi: Que quereis que vos faça?");
    b->dados[SAMUEL2].capitulos[21].versos[5] = _("Responderam ao rei: Quanto ao homem que nos consumia, e procurava destruir-nos, de modo que não pudéssemos subsistir em termo algum de Israel,");
    b->dados[SAMUEL2].capitulos[21].versos[6] = _("de seus filhos se nos dêem sete homens, para que os enforquemos ao Senhor em Gibeá de Saul, o eleito do Senhor. E o rei disse: Eu os darei.");
    b->dados[SAMUEL2].capitulos[21].versos[7] = _("O rei, porém, poupou a Mefibosete, filho de Jônatas, filho de Saul, por causa do juramento do Senhor que entre eles houvera, isto é, entre Davi e Jônatas, filho de Saul.");
    b->dados[SAMUEL2].capitulos[21].versos[8] = _("Mas o rei tomou os dois filhos de Rizpa, filha de Aías, que ela tivera de Saul, a saber, a Armoni e a Mefibosete, como também os cinco filhos de Merabe, filha de Saul, que ela tivera de Adriel, filho de Barzilai, meolatita,");
    b->dados[SAMUEL2].capitulos[21].versos[9] = _("e os entregou na mão dos gibeonitas, os quais os enforcaram no monte, perante o Senhor; e os sete caíram todos juntos. Foi nos primeiros dias da sega que foram mortos, no princípio a sega da cevada.");
    b->dados[SAMUEL2].capitulos[21].versos[10] = _("Então Rizpa, filha de Aías, tomando um pano de cilício, estendeu-o para si sobre uma pedra e, desde o princípio da sega até que a água caiu do céu sobre os corpos, não deixou que se aproximassem deles as aves do céu de dia, nem os animais do campo de noite:");
    b->dados[SAMUEL2].capitulos[21].versos[11] = _("Quando foi anunciado a Davi o que fizera Rizpa, filha de Aías, concubina de Saul,");
    b->dados[SAMUEL2].capitulos[21].versos[12] = _("ele foi e tomou os ossos de Saul e os de Jônatas seu filho, aos homens de Jabes-Gileade, que os haviam furtado da praça de Bete-Seã, onde os filisteus os tinham pendurado quando mataram a Saul em Gilboa;");
    b->dados[SAMUEL2].capitulos[21].versos[13] = _("e trouxe dali os ossos de Saul e os de Jônatas seu filho; e ajuntaram a eles também os ossos dos enforcados.");
    b->dados[SAMUEL2].capitulos[21].versos[14] = _("Enterraram os ossos de Saul e de Jônatas seu filho, na terra de Benjamim, em Zela, na sepultura de Quis, seu pai; e fizeram tudo o que o rei ordenara. Depois disto Deus se aplacou para com a terra.");
    b->dados[SAMUEL2].capitulos[21].versos[15] = _("De novo tiveram os filisteus uma guerra contra Israel. E desceu Davi, e com ele os seus servos; e tanto pelejara contra os filisteus, que Davi se cansou.");
    b->dados[SAMUEL2].capitulos[21].versos[16] = _("E Isbi-Benobe, que era dos filhos do gigante, cuja lança tinha o peso de trezentos, siclos de bronze, e que cingia uma espada nova, intentou matar Davi.");
    b->dados[SAMUEL2].capitulos[21].versos[17] = _("Porém, Abisai, filho de Zeruia, o socorreu; e, ferindo ao filisteu, o matou. Então os homens de Davi lhe juraram, dizendo: Nunca mais sairás conosco à batalha, para que não apagues a lâmpada de Israel.");
    b->dados[SAMUEL2].capitulos[21].versos[18] = _("Aconteceu depois disto que houve em Gobe ainda outra peleja contra os filisteus; então Sibecai, o husatita, matou Safe, que era dos filhos do gigante.");
    b->dados[SAMUEL2].capitulos[21].versos[19] = _("Houve mais outra peleja contra os filisteus em Gobe; e El-Hanã, filho de Jaaré-Oregim, o belemita, matou Golias, o giteu, de cuja lança a haste era como órgão de tecelão.");
    b->dados[SAMUEL2].capitulos[21].versos[20] = _("Houve ainda também outra peleja em Gate, onde estava um homem de alta estatura, que tinha seis dedos em cada mão, e seis em cada pé, vinte e quatro por todos; também este era descendente do gigante.");
    b->dados[SAMUEL2].capitulos[21].versos[21] = _("Tendo ele desafiado a Israel, Jônatas, filho de Simei, irmão de Davi, o matou.");
    b->dados[SAMUEL2].capitulos[21].versos[22] = _("Estes quatro nasceram ao gigante em Gate; e caíram pela mão de Davi e pela mão de seus servos.");

    b->dados[SAMUEL2].capitulos[22].versos[1] = _("Davi dirigiu ao Senhor as palavras deste cântico, no dia em que o Senhor o livrou das mãos de todos os seus inimigos e das mãos de Saul, dizendo:");
    b->dados[SAMUEL2].capitulos[22].versos[2] = _("O Senhor é o meu rochedo, a minha fortaleza e o meu libertador.");
    b->dados[SAMUEL2].capitulos[22].versos[3] = _("É meu Deus, a minha rocha, nele confiarei; é o meu escudo, e a força da minha salvação, o meu alto retiro, e o meu refúgio. O meu Salvador; da violência tu me livras.");
    b->dados[SAMUEL2].capitulos[22].versos[4] = _("Ao Senhor invocarei, pois é digno de louvor; assim serei salvo dos meus inimigos.");
    b->dados[SAMUEL2].capitulos[22].versos[5] = _("As ondas da morte me cercaram, as torrentes de Belial me atemorizaram.");
    b->dados[SAMUEL2].capitulos[22].versos[6] = _("Cordas do Seol me cingiram, laços de morte me envolveram.");
    b->dados[SAMUEL2].capitulos[22].versos[7] = _("Na minha angústia invoquei ao Senhor; sim, a meu Deus clamei; do seu templo ouviu ele a minha voz, e o meu clamor chegou aos seus ouvidos.");
    b->dados[SAMUEL2].capitulos[22].versos[8] = _("Então se abalou e tremeu a terra, os fundamentos dos céus se moveram; abalaram-se porque ele se irou.");
    b->dados[SAMUEL2].capitulos[22].versos[9] = _("Das suas narinas subiu fumaça, e da sua boca um fogo devorador, que pôs carvões em chamas.");
    b->dados[SAMUEL2].capitulos[22].versos[10] = _("Ele abaixou os céus, e desceu; e havia escuridão debaixo dos seus pés.");
    b->dados[SAMUEL2].capitulos[22].versos[11] = _("Montou num querubim, e voou; apareceu sobre as asas do vento.");
    b->dados[SAMUEL2].capitulos[22].versos[12] = _("E por tendas pôs trevas ao redor de si, ajuntamento de águas, espessas nuvens do céu.");
    b->dados[SAMUEL2].capitulos[22].versos[13] = _("Pelo resplendor da sua presença acenderam-se brasas de fogo.");
    b->dados[SAMUEL2].capitulos[22].versos[14] = _("Do céu trovejou o Senhor, o Altíssimo fez soar a sua voz.");
    b->dados[SAMUEL2].capitulos[22].versos[15] = _("Disparou flechas, e os dissipou; raios, e os desbaratou.");
    b->dados[SAMUEL2].capitulos[22].versos[16] = _("Então apareceram as profundezas do mar; os fundamentos do mundo se descobriram, pela repreensão do Senhor, pelo assopro do vento das suas narinas.");
    b->dados[SAMUEL2].capitulos[22].versos[17] = _("Estendeu do alto a sua mão e tomou-me; tirou-me das muitas águas.");
    b->dados[SAMUEL2].capitulos[22].versos[18] = _("Livrou-me do meu possante inimigo, e daqueles que me odiavam; porque eram fortes demais para mim.");
    b->dados[SAMUEL2].capitulos[22].versos[19] = _("Encontraram-me no dia da minha calamidade, porém o Senhor se fez o meu esteio.");
    b->dados[SAMUEL2].capitulos[22].versos[20] = _("Conduziu-me para um lugar espaçoso; livrou-me, porque tinha prazer em mim.");
    b->dados[SAMUEL2].capitulos[22].versos[21] = _("Recompensou-me o Senhor conforme a minha justiça; conforme a pureza e minhas mãos me retribuiu.");
    b->dados[SAMUEL2].capitulos[22].versos[22] = _("Porque guardei os caminhos do Senhor, e não me apartei impiamente do meu Deus.");
    b->dados[SAMUEL2].capitulos[22].versos[23] = _("Pois todos os seus preceitos estavam diante de mim, e dos seus estatutos não me desviei.");
    b->dados[SAMUEL2].capitulos[22].versos[24] = _("Fui perfeito para com ele, e guardei-me da minha iniqüidade.");
    b->dados[SAMUEL2].capitulos[22].versos[25] = _("Por isso me retribuiu o Senhor conforme a minha justiça, conforme a minha pureza diante dos meus olhos.");
    b->dados[SAMUEL2].capitulos[22].versos[26] = _("Para com o benigno te mostras benigno; para com o perfeito te mostras perfeito,");
    b->dados[SAMUEL2].capitulos[22].versos[27] = _("para com o puro te mostras puro, mas para com o perverso te mostras avesso.");
    b->dados[SAMUEL2].capitulos[22].versos[28] = _("Livrarás o povo que se humilha, mas teus olhos são contra os altivos, e tu os abaterás.");
    b->dados[SAMUEL2].capitulos[22].versos[29] = _("Porque tu, Senhor, és a minha candeia; e o Senhor alumiará as minhas trevas.");
    b->dados[SAMUEL2].capitulos[22].versos[30] = _("Pois contigo passarei pelo meio dum esquadrão; com o meu Deus transporei um muro.");
    b->dados[SAMUEL2].capitulos[22].versos[31] = _("Quanto a Deus, o seu caminho é perfeito, e a palavra do Senhor é fiel; é ele o escudo de todos os que nele se refugiam.");
    b->dados[SAMUEL2].capitulos[22].versos[32] = _("Pois quem é Deus, senão o Senhor? e quem é rocha, senão o nosso Deus?");
    b->dados[SAMUEL2].capitulos[22].versos[33] = _("Deus é a minha grande fortaleza; e ele torna perfeito o meu caminho.");
    b->dados[SAMUEL2].capitulos[22].versos[34] = _("Faz ele os meus pés como os das gazelas, e me põe sobre as minhas alturas.");
    b->dados[SAMUEL2].capitulos[22].versos[35] = _("Ele instrui as minhas mãos para a peleja, de modo que os meus braços podem entesar um arco de bronze.");
    b->dados[SAMUEL2].capitulos[22].versos[36] = _("Também me deste o escudo da tua salvação, e tua brandura me engrandece.");
    b->dados[SAMUEL2].capitulos[22].versos[37] = _("Alargaste os meus passos debaixo de mim, e não vacilaram os meus artelhos.");
    b->dados[SAMUEL2].capitulos[22].versos[38] = _("Persegui os meus inimigos e os destruí, e nunca voltei atrás sem que os consumisse.");
    b->dados[SAMUEL2].capitulos[22].versos[39] = _("Eu os consumi, e os atravessei, de modo que nunca mais se levantaram; sim, cairam debaixo dos meus pés.");
    b->dados[SAMUEL2].capitulos[22].versos[40] = _("Pois tu me cingiste de força para a peleja; prostraste debaixo de mim os que se levantaram contra mim.");
    b->dados[SAMUEL2].capitulos[22].versos[41] = _("Fizeste que me voltassem as costas os meus inimigos, aqueles que me odiavam, para que eu os destruísse.");
    b->dados[SAMUEL2].capitulos[22].versos[42] = _("Olharam ao redor, mas não houve quem os salvasse; clamaram ao Senhor, mas ele não lhes respondeu.");
    b->dados[SAMUEL2].capitulos[22].versos[43] = _("Então os moí como o pó da terra; como a lama das ruas os trilhei e dissipei.");
    b->dados[SAMUEL2].capitulos[22].versos[44] = _("Também me livraste das contendas do meu povo; guardaste-me para ser o cabeça das nações; um povo que eu não conhecia me serviu.");
    b->dados[SAMUEL2].capitulos[22].versos[45] = _("Estrangeiros, com adulação, se submeteram a mim; ao ouvirem de mim, me obedeceram.");
    b->dados[SAMUEL2].capitulos[22].versos[46] = _("Os estrangeiros desfaleceram e, tremendo, sairam os seus esconderijos.");
    b->dados[SAMUEL2].capitulos[22].versos[47] = _("O Senhor vive; bendita seja a minha rocha, e exaltado seja Deus, a rocha da minha salvação,");
    b->dados[SAMUEL2].capitulos[22].versos[48] = _("o Deus que me deu vingança, e sujeitou povos debaixo de mim,");
    b->dados[SAMUEL2].capitulos[22].versos[49] = _("e me tirou dentre os meus inimigos; porque tu me exaltaste sobre os meus adversários; tu me livraste do homem violento.");
    b->dados[SAMUEL2].capitulos[22].versos[50] = _("Por isso, ó Senhor, louvar-te-ei entre as nações, e entoarei louvores ao teu nome.");
    b->dados[SAMUEL2].capitulos[22].versos[51] = _("Ele dá grande livramento a seu rei, e usa de benignidade para com o seu ungido, para com Davi e a sua descendência para sempre.");

    b->dados[SAMUEL2].capitulos[23].versos[1] = _("São estas as últimas palavras de Davi: Diz Davi, filho de Jessé, diz a homem que foi exaltado, o ungido do Deus de Jacó, o suave salmista de Israel.");
    b->dados[SAMUEL2].capitulos[23].versos[2] = _("O Espírito do Senhor fala por mim, e a sua palavra está na minha língua.");
    b->dados[SAMUEL2].capitulos[23].versos[3] = _("Falou o Deus de Israel, a Rocha de Israel me disse: Quando um justo governa sobre os homens, quando governa no temor de Deus,");
    b->dados[SAMUEL2].capitulos[23].versos[4] = _("será como a luz da manhã ao sair do sol, da manhã sem nuvens, quando, depois da chuva, pelo resplendor do sol, a erva brota da terra.");
    b->dados[SAMUEL2].capitulos[23].versos[5] = _("Pois não é assim a minha casa para com Deus? Porque estabeleceu comigo um pacto eterno, em tudo bem ordenado e seguro; pois não fará ele prosperar toda a minha salvação e todo o meu desejo?");
    b->dados[SAMUEL2].capitulos[23].versos[6] = _("Porém os ímpios todos serão como os espinhos, que se lançam fora, porque não se pode tocar neles;");
    b->dados[SAMUEL2].capitulos[23].versos[7] = _("mas qualquer que os tocar se armará de ferro e da haste de uma lança; e a fogo serão totalmente queimados no mesmo lugar.");
    b->dados[SAMUEL2].capitulos[23].versos[8] = _("São estes os nomes dos valentes de Davi: Josebe-Bassebete, o taquemonita; era este principal dos três; foi ele que, com a lança, matou oitocentos de uma vez.");
    b->dados[SAMUEL2].capitulos[23].versos[9] = _("Depois dele Eleazar, filho de Dodó, filho de Aoí, um dos três valentes que estavam com Davi, quando desafiaram os filisteus que se haviam reunido para a peleja, enquanto os homens de Israel se retiravam.");
    b->dados[SAMUEL2].capitulos[23].versos[10] = _("Este se levantou, e feriu os filisteus, até lhe cansar a mão e ficar pegada à espada; e naquele dia o Senhor operou um grande livramento; e o povo voltou para junto de Eleazar, somente para tomar o despojo.");
    b->dados[SAMUEL2].capitulos[23].versos[11] = _("Depois dele era Samá, filho de Agé, o hararita. Os filisteus se haviam ajuntado em Leí, onde havia um terreno cheio de lentilhas; e o povo fugiu de diante dos filisteus.");
    b->dados[SAMUEL2].capitulos[23].versos[12] = _("Samá, porém, pondo-se no meio daquele terreno, defendeu-o e matou os filisteus, e o Senhor efetuou um grande livramento.");
    b->dados[SAMUEL2].capitulos[23].versos[13] = _("Também três dos trinta cabeças desceram, no tempo da sega, e foram ter com Davi, à caverna de Adulão; e a tropa dos filisteus acampara no vale de Refaim.");
    b->dados[SAMUEL2].capitulos[23].versos[14] = _("Davi estava então no lugar forte, e a guarnição dos filisteus estava em Belém.");
    b->dados[SAMUEL2].capitulos[23].versos[15] = _("E Davi, com saudade, exclamou: Quem me dera beber da água da cisterna que está junto a porta de Belém!");
    b->dados[SAMUEL2].capitulos[23].versos[16] = _("Então aqueles três valentes romperam pelo arraial dos filisteus, tiraram água da cisterna que está junto a porta de Belém, e a trouxeram a Davi; porém ele não quis bebê-la, mas derramou-a perante o Senhor;");
    b->dados[SAMUEL2].capitulos[23].versos[17] = _("e disse: Longe de mim, ó Senhor, que eu tal faça! Beberia eu o sangue dos homens que foram com risco das suas vidas? De maneira que não a quis beber. Isto fizeram aqueles três valentes.");
    b->dados[SAMUEL2].capitulos[23].versos[18] = _("Ora, Abisai, irmão de Joabe, filho de Zeruia, era chefe dos trinta; e este alçou a sua lança contra trezentos, e os matou, e tinha nome entre os três.");
    b->dados[SAMUEL2].capitulos[23].versos[19] = _("Porventura não era este o mais nobre dentre os trinta? portanto se tornou o chefe deles; porém aos primeiros três não chegou.");
    b->dados[SAMUEL2].capitulos[23].versos[20] = _("Também Benaías, filho de Jeoiada, filho dum homem de Cabzeel, valoroso e de grandes feitos, matou os dois filhos de Ariel de Moabe; depois desceu, e matou um leão dentro duma cova, no tempo da neve.");
    b->dados[SAMUEL2].capitulos[23].versos[21] = _("Matou também um egípcio, homem de temível aspecto; tinha este uma lança na mão, mas Benaías desceu a ele com um cajado, arrancou-lhe da mão a lança, e com ela o matou.");
    b->dados[SAMUEL2].capitulos[23].versos[22] = _("Estas coisas fez Benaías, filho de Jeoiada, pelo que teve nome entre os três valentes.");
    b->dados[SAMUEL2].capitulos[23].versos[23] = _("Dentre os trinta ele era o mais afamado, porém aos três primeiros não chegou. Mas Davi o pôs sobre os seus guardas.");
    b->dados[SAMUEL2].capitulos[23].versos[24] = _("Asael, irmão de Joabe, era um dos trinta; El-Hanã, filho de Dodó, de Belém;");
    b->dados[SAMUEL2].capitulos[23].versos[25] = _("Samá, o harodita; Elica, o harodita;");
    b->dados[SAMUEL2].capitulos[23].versos[26] = _("Jelez, o paltita; Ira, filho de Iques, o tecoíta;");
    b->dados[SAMUEL2].capitulos[23].versos[27] = _("Abiezer, o anatotita; Mebunai, o husatita;");
    b->dados[SAMUEL2].capitulos[23].versos[28] = _("Zalmom, o aoíta; Maarai, o netofatita;");
    b->dados[SAMUEL2].capitulos[23].versos[29] = _("Helebe, filho de Baaná, o netofatita; Itai, filho de Ribai, de Gibeá dos filhos de Benjamim;");
    b->dados[SAMUEL2].capitulos[23].versos[30] = _("Benaías, o piratonita; Hidai, das torrentes de Gaás;");
    b->dados[SAMUEL2].capitulos[23].versos[31] = _("Abi-Albom, o arbatita; Azmavete, o barumita;");
    b->dados[SAMUEL2].capitulos[23].versos[32] = _("Eliabá, o saalbonita; Bene-Jásen; e Jônatas;");
    b->dados[SAMUEL2].capitulos[23].versos[33] = _("Samá, o hararita; Aião, filho de Sarar, o hararita;");
    b->dados[SAMUEL2].capitulos[23].versos[34] = _("Elifelete, filho de Acasbai, filho do maacatita; Eliã, filho de Aitofel, o gilonita;");
    b->dados[SAMUEL2].capitulos[23].versos[35] = _("Hezrai, o carmelita; Paarai, o arbita;");
    b->dados[SAMUEL2].capitulos[23].versos[36] = _("Igal, filho de Natã, de Zobá; Bani, o gadita;");
    b->dados[SAMUEL2].capitulos[23].versos[37] = _("Zeleque, o amonita; Naarai, o beerotita, o que trazia as armas de Joabe, filho de Zeruia;");
    b->dados[SAMUEL2].capitulos[23].versos[38] = _("Ira, o itrita; Garebe, o itrita;");
    b->dados[SAMUEL2].capitulos[23].versos[39] = _("Urias, o heteu; trinta e sete ao todo.");

    b->dados[SAMUEL2].capitulos[24].versos[1] = _("A ira do Senhor tornou a acender-se contra Israel, e o Senhor incitou a Davi contra eles, dizendo: Vai, numera a Israel e a Judá.");
    b->dados[SAMUEL2].capitulos[24].versos[2] = _("Disse, pois, o rei a Joabe, chefe do exército, que estava com ele: Percorre todas as tribos de Israel, desde Dã até Berseba, e numera o povo, para que eu saiba o seu número.");
    b->dados[SAMUEL2].capitulos[24].versos[3] = _("Então disse Joabe ao rei: Ora, multiplique o Senhor teu Deus a este povo cem vezes tanto quanto agora é, e os olhos do rei meu senhor o vejam. Mas por que tem prazer nisto o rei meu senhor;");
    b->dados[SAMUEL2].capitulos[24].versos[4] = _("Todavia a palavra do rei prevaleceu contra Joabe, e contra os chefes do exército; Joabe, pois, saiu com os chefes do exército da presença do rei para numerar o povo de Israel.");
    b->dados[SAMUEL2].capitulos[24].versos[5] = _("Tendo eles passado o Jordão, acamparam-se em Aroer, à direita da cidade que está no meio do vale de Gade e na direção de Jazer;");
    b->dados[SAMUEL2].capitulos[24].versos[6] = _("em seguida foram a Gileade, e a terra de Tatim-Hódsi; dali foram a Da-Jaã, e ao redor até Sidom;");
    b->dados[SAMUEL2].capitulos[24].versos[7] = _("depois foram à fortaleza de Tiro, e a todas as cidades dos heveus e dos cananeus; e saíram para a banda do sul de Judá, em Berseba.");
    b->dados[SAMUEL2].capitulos[24].versos[8] = _("Assim, tendo percorrido todo o país, voltaram a Jerusalém, ao cabo de nove meses e vinte dias.");
    b->dados[SAMUEL2].capitulos[24].versos[9] = _("Joabe, pois, deu ao rei o resultado da numeração do povo. E havia em Israel oitocentos mil homens valorosos, que arrancavam da espada; e os homens de Judá eram quinhentos mil.");
    b->dados[SAMUEL2].capitulos[24].versos[10] = _("Mas o coração de Davi o acusou depois de haver ele numerado o povo; e disse Davi ao Senhor: Muito pequei no que fiz; porém agora, ó Senhor, rogo-te que perdoes a iniqüidade do teu servo, porque tenho procedido mui nesciamente.");
    b->dados[SAMUEL2].capitulos[24].versos[11] = _("Quando, pois, Davi se levantou pela manhã, veio a palavra do Senhor ao profeta Gade, vidente de Davi, dizendo:");
    b->dados[SAMUEL2].capitulos[24].versos[12] = _("Vai, e dize a Davi: Assim diz o Senhor: Três coisas te ofereço; escolhe qual delas queres que eu te faça.");
    b->dados[SAMUEL2].capitulos[24].versos[13] = _("Veio, pois, Gade a Davi, e fez-lho saber dizendo-lhe: Queres que te venham sete anos de fome na tua terra; ou que por três meses fujas diante de teus inimigos, enquanto estes te perseguirem; ou que por três dias haja peste na tua terra? Delibera agora, e vê que resposta hei de dar àquele que me enviou.");
    b->dados[SAMUEL2].capitulos[24].versos[14] = _("Respondeu Davi a Gade: Estou em grande angústia; porém caiamos nas mãos do Senhor, porque muitas são as suas misericórdias; mas nas mãos dos homens não caia eu.");
    b->dados[SAMUEL2].capitulos[24].versos[15] = _("Então enviou o Senhor a peste sobre Israel, desde a manhã até o tempo determinado; e morreram do povo, desde Dã até Berseba, setenta mil homens.");
    b->dados[SAMUEL2].capitulos[24].versos[16] = _("Ora, quando o anjo estendeu a mão sobre Jerusalém, para a destruir, o Senhor se arrependeu daquele mal; e disse ao anjo que fazia a destruição entre o povo: Basta; retira agora a tua mão. E o anjo do Senhor estava junto à eira de Araúna, o jebuseu.");
    b->dados[SAMUEL2].capitulos[24].versos[17] = _("E, vendo Davi ao anjo que feria o povo, falou ao Senhor, dizendo: Eis que eu pequei, e procedi iniquamente; porém estas ovelhas, que fizeram? Seja, pois, a tua mão contra mim, e contra a casa de meu pai.");
    b->dados[SAMUEL2].capitulos[24].versos[18] = _("Naquele mesmo dia veio Gade a Davi, e lhe disse: Sobe, levanta ao Senhor um altar na eira de Araúna, o jebuseu:");
    b->dados[SAMUEL2].capitulos[24].versos[19] = _("Subiu, pois, Davi, conforme a palavra de Gade, como o Senhor havia ordenado.");
    b->dados[SAMUEL2].capitulos[24].versos[20] = _("E olhando Araúna, viu que vinham ter com ele o rei e os seus servos; saiu, pois, e inclinou-se diante do rei com o rosto em terra.");
    b->dados[SAMUEL2].capitulos[24].versos[21] = _("Perguntou Araúna: Por que vem o rei meu senhor ao seu servo? Respondeu Davi: Para comprar de ti a eira, a fim de edificar nela um altar ao Senhor, para que a praga cesse de sobre o povo.");
    b->dados[SAMUEL2].capitulos[24].versos[22] = _("Então disse Araúna a Davi: Tome e ofereça o rei meu senhor o que bem lhe parecer; eis aí os bois para o holocausto, e os trilhos e os aparelhos dos bois para lenha.");
    b->dados[SAMUEL2].capitulos[24].versos[23] = _("Tudo isto, ó rei, Araúna te oferece. Disse mais Araúna ao rei: O Senhor teu Deus tome prazer em ti.");
    b->dados[SAMUEL2].capitulos[24].versos[24] = _("Mas o rei disse a Araúna: Não! antes to comprarei pelo seu valor, porque não oferecerei ao Senhor meu Deus holocaustos que não me custem nada. Comprou, pois, Davi a eira e os bois por cinqüenta siclos de prata.");
    b->dados[SAMUEL2].capitulos[24].versos[25] = _("E edificou ali um altar ao Senhor, e ofereceu holocaustos e ofertas pacíficas. Assim o Senhor se tornou propício para com a terra, e cessou aquela praga de sobre Israel.");

}
